import React, { useState } from 'react';
import { generateVideo } from '../services/geminiService';

const VideoGenView: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16'>('16:9');
  const [startImage, setStartImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [status, setStatus] = useState('');

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setStartImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!prompt && !startImage) return;
    setLoading(true);
    setStatus('Initializing Veo engine...');
    try {
      const url = await generateVideo(prompt, aspectRatio, startImage || undefined);
      setVideoUrl(url);
    } catch (err) {
      console.error(err);
      setStatus('Generation failed. Ensure you have a valid API key.');
    } finally {
      setLoading(false);
      setStatus('');
    }
  };

  return (
    <div className="max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="lg:col-span-4 space-y-6">
        <div className="space-y-4">
          <label className="text-sm font-bold text-gray-400 uppercase tracking-widest">Creative Prompt</label>
          <textarea
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
            placeholder="Describe your cinematic vision..."
            className="w-full h-32 p-4 glass-panel rounded-xl border-white/10 focus:border-indigo-500/50 outline-none resize-none"
          />
        </div>

        <div className="space-y-4">
          <label className="text-sm font-bold text-gray-400 uppercase tracking-widest">Aspect Ratio</label>
          <div className="flex gap-2">
            <button
              onClick={() => setAspectRatio('16:9')}
              className={`flex-1 py-3 rounded-xl border transition-all ${aspectRatio === '16:9' ? 'bg-indigo-500/20 border-indigo-500 text-white' : 'bg-white/5 border-white/10 text-gray-400'}`}
            >
              Landscape (16:9)
            </button>
            <button
              onClick={() => setAspectRatio('9:16')}
              className={`flex-1 py-3 rounded-xl border transition-all ${aspectRatio === '9:16' ? 'bg-indigo-500/20 border-indigo-500 text-white' : 'bg-white/5 border-white/10 text-gray-400'}`}
            >
              Portrait (9:16)
            </button>
          </div>
        </div>

        <div className="space-y-4">
          <label className="text-sm font-bold text-gray-400 uppercase tracking-widest">Reference Image (Optional)</label>
          <div className="relative h-32 w-full rounded-xl border border-dashed border-white/20 flex flex-col items-center justify-center hover:border-indigo-500/50 transition-colors overflow-hidden">
            {startImage ? (
              <img src={startImage} className="absolute inset-0 w-full h-full object-cover" alt="Source" />
            ) : (
              <span className="text-gray-500 text-sm">Click to upload starting frame</span>
            )}
            <input type="file" accept="image/*" onChange={handleFileChange} className="absolute inset-0 opacity-0 cursor-pointer" />
          </div>
          {startImage && <button onClick={() => setStartImage(null)} className="text-xs text-red-400">Remove image</button>}
        </div>

        <button
