import React, { useState, useRef, useEffect, useCallback } from 'react';
import { GoogleGenAI, Modality } from '@google/genai';

const LiveView: React.FC = () => {
  const [active, setActive] = useState(false);
  const [transcripts, setTranscripts] = useState<string[]>([]);
  const audioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);

  const decode = (base64: string) => {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  const decodeAudioData = async (
    data: Uint8Array,
    ctx: AudioContext,
    sampleRate: number,
    numChannels: number,
  ): Promise<AudioBuffer> => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  };

  const encode = (bytes: Uint8Array) => {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  };

  const stopConversation = () => {
    if (sessionRef.current) {
      sessionRef.current.close();
      sessionRef.current = null;
    }
    setActive(false);
  };

  const startConversation = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    const outputNode = audioContextRef.current.createGain();
    outputNode.connect(audioContextRef.current.destination);

    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

    const sessionPromise = ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      callbacks: {
        onopen: () => {
          setActive(true);
          const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
          const source = inputCtx.createMediaStreamSource(stream);
          const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

          scriptProcessor.onaudioprocess = (e) => {
            const inputData = e.inputBuffer.getChannelData(0);
            const int16 = new Int16Array(inputData.length);
            for (let i = 0; i < inputData.length; i++) {
                int16[i] = inputData[i] * 32768;
            }
            const pcmBlob = {
              data: encode(new Uint8Array(int16.buffer)),
              mimeType: 'audio/pcm;rate=16000',
            };
            sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
          };
          source.connect(scriptProcessor);
          scriptProcessor.connect(inputCtx.destination);
        },
        onmessage: async (message) => {
          if (message.serverContent?.outputTranscription) {
            setTranscripts(prev => [...prev, `Gemini: ${message.serverContent?.outputTranscription?.text}`]);
          }
          if (message.serverContent?.inputTranscription) {
            setTranscripts(prev => [...prev, `You: ${message.serverContent?.inputTranscription?.text}`]);
          }

          const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
          if (audioData && audioContextRef.current) {
            const buffer = await decodeAudioData(decode(audioData), audioContextRef.current, 24000, 1);
            const source = audioContextRef.current.createBufferSource();
            source.buffer = buffer;
            source.connect(outputNode);

            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, audioContextRef.current.currentTime);
            source.start(nextStartTimeRef.current);
            nextStartTimeRef.current += buffer.duration;
            sourcesRef.current.add(source);
            source.onended = () => sourcesRef.current.delete(source);
          }

          if (message.serverContent?.interrupted) {
            sourcesRef.current.forEach(s => s.stop());
            sourcesRef.current.clear();
            nextStartTimeRef.current = 0;
          }
        },
        onerror: (e) => {
          console.error(e);
          setActive(false);
        },
        onclose: () => setActive(false),
      },
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
        },
        outputAudioTranscription: {},
        inputAudioTranscription: {},
        systemInstruction: "You are a highly capable AI assistant in a low-latency voice environment. Be concise and conversational."
      }
    });

    sessionRef.current = await sessionPromise;
  };

  return (
    <div className="max-w-4xl mx-auto h-[70vh] flex flex-col space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex-1 glass-panel rounded-3xl border-white/5 p-8 flex flex-col items-center justify-center relative overflow-hidden">

        <div className={`w-48 h-48 rounded-full border-4 flex items-center justify-center transition-all duration-700 ${active ? 'border-indigo-500 shadow-[0_0_50px_rgba(99,102,241,0.4)] scale-110' : 'border-white/10 grayscale opacity-50'}`}>
           <div className={`w-32 h-32 rounded-full accent-gradient animate-pulse flex items-center justify-center`}>
              <svg className="w-16 h-16 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
           </div>
        </div>

        <div className="mt-12 text-center space-y-4">
          <h3 className="text-2xl font-bold font-outfit">{active ? 'Assistant Listening' : 'Voice Interaction Inactive'}</h3>
          <p className="text-gray-400 max-w-sm">Experience the future of human-AI interaction with real-time audio and low-latency response.</p>
        </div>

        <div className="absolute bottom-8 left-8 right-8 flex justify-center">
            <button
                onClick={active ? stopConversation : startConversation}
                className={`px-12 py-4 rounded-2xl font-bold transition-all shadow-xl ${active ? 'bg-red-500/20 border border-red-500/50 text-red-400 hover:bg-red-500/30' : 'accent-gradient text-white hover:scale-105'}`}
            >
                {active ? 'End Session' : 'Start Real-time Conversation'}
            </button>
        </div>
      </div>

      <div className="h-48 glass-panel rounded-2xl border-white/5 p-4 overflow-y-auto space-y-2">
        <p className="text-xs text-indigo-400 font-bold uppercase tracking-widest mb-4">Live Transcription</p>
        {transcripts.map((t, i) => (
          <div key={i} className={`text-sm ${t.startsWith('You:') ? 'text-gray-400' : 'text-indigo-300 font-medium'}`}>
            {t}
          </div>
        ))}
        {transcripts.length === 0 && <p className="text-gray-600 italic">No activity yet...</p>}
      </div>
    </div>
  );
};

