import React, { useState, useRef } from 'react';
import { ELEVEN_LABS_VOICES, VoiceProfile } from '../types';
import { generateTTS } from '../services/geminiService';

const TTSView: React.FC = () => {
  const [text, setText] = useState('');
  const [selectedVoice, setSelectedVoice] = useState<VoiceProfile>(ELEVEN_LABS_VOICES[0]);
  const [loading, setLoading] = useState(false);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const encodeWAV = (samples: Float32Array, sampleRate: number) => {
    const buffer = new ArrayBuffer(44 + samples.length * 2);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) {
        v.setUint8(offset + i, string.charCodeAt(i));
      }
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 32 + samples.length * 2, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, samples.length * 2, true);
    let offset = 44;
    for (let i = 0; i < samples.length; i++, offset += 2) {
      const s = Math.max(-1, Math.min(1, samples[i]));
      view.setInt16(offset, s < 0 ? s * 0x8000 : s * 0x7FFF, true);
    }
    return buffer;
  };

  const handleGenerate = async () => {
    if (!text) return;
    setLoading(true);
    try {
      const base64Audio = await generateTTS(text, selectedVoice.geminiVoice);
      if (base64Audio) {
        const binaryString = atob(base64Audio);
        const bytes = new Uint8Array(binaryString.length);
        const int16Data = new Int16Array(bytes.buffer);
        for (let i = 0; i < binaryString.length; i++) {
          bytes[i] = binaryString.charCodeAt(i);
        }

        const floatData = new Float32Array(int16Data.length);
        for (let i = 0; i < int16Data.length; i++) {
          floatData[i] = int16Data[i] / 32768.0;
        }

        const wavBuffer = encodeWAV(floatData, 24000);
        const blob = new Blob([wavBuffer], { type: 'audio/wav' });
        const url = URL.createObjectURL(blob);
        setAudioUrl(url);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-6">
          <div className="space-y-2">
            <label className="text-sm font-bold text-gray-400 uppercase tracking-widest">Input Text</label>
            <textarea
              value={text}
              onChange={(e) => setText(e.target.value)}
              placeholder="Enter the text you want to synthesize..."
              className="w-full h-64 p-6 glass-panel rounded-2xl border-white/10 focus:border-indigo-500/50 focus:ring-1 focus:ring-indigo-500/50 outline-none resize-none transition-all"
            />
          </div>

          <button
            onClick={handleGenerate}
            disabled={loading || !text}
            className={`w-full py-4 accent-gradient rounded-2xl font-bold flex items-center justify-center gap-3 transition-all ${loading ? 'opacity-50 cursor-not-allowed' : 'hover:shadow-[0_0_20px_rgba(99,102,241,0.3)]'}`}
          >
            {loading ? (
              <><div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" /> Synthesizing...</>
            ) : (
              <><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg> Generate Voice</>
            )}
          </button>

          {audioUrl && (
            <div className="p-6 glass-panel rounded-2xl border-indigo-500/30 flex flex-col md:flex-row items-center gap-4 animate-in slide-in-from-top-2">
              <audio ref={audioRef} src={audioUrl} controls className="flex-1 w-full" />
              <a 
                href={audioUrl} 
                download={`voice-${selectedVoice.name.toLowerCase()}.wav`}
                className="px-6 py-2 bg-white/5 border border-white/10 rounded-xl hover:bg-white/10 transition-colors flex items-center gap-2 text-sm font-bold"
              >
                <svg className="w-4 h-4 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                Download
              </a>
            </div>
          )}
        </div>

        <div className="space-y-6">
          <label className="text-sm font-bold text-gray-400 uppercase tracking-widest">Voice Profile</label>
          <div className="space-y-3">
            {ELEVEN_LABS_VOICES.map((voice) => (
              <button
                key={voice.id}
                onClick={() => {
                  setSelectedVoice(voice);
                  setAudioUrl(null);
                }}
                className={`w-full p-4 rounded-xl text-left border transition-all ${
                  selectedVoice.id === voice.id 
                  ? 'bg-indigo-500/20 border-indigo-500 text-white' 
                  : 'bg-white/5 border-white/10 text-gray-400 hover:bg-white/10'
                }`}
              >
                <p className="font-bold">{voice.name}</p>
                <p className="text-xs opacity-60">ID: {voice.id.slice(0, 10)}...</p>
                <p className="text-xs mt-1 text-indigo-300">Engine: {voice.geminiVoice}</p>
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

