import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, Modality } from '@google/genai';

interface ResponseHistory {
  id: string;
  transcript: string;
  audioUrl: string | null;
  timestamp: Date;
}

const LiveView: React.FC = () => {
  const [active, setActive] = useState(false);
  const [responses, setResponses] = useState<ResponseHistory[]>([]);
  const [currentTurnAudioChunks, setCurrentTurnAudioChunks] = useState<Uint8Array[]>([]);
  const audioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);
  const [currentOutputTranscription, setCurrentOutputTranscription] = useState('');

  const decode = (base64: string) => {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  const decodeAudioData = async (
    data: Uint8Array,
    ctx: AudioContext,
    sampleRate: number,
    numChannels: number,
  ): Promise<AudioBuffer> => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  };

  const encode = (bytes: Uint8Array) => {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  };

  const encodeWAV = (chunks: Uint8Array[], sampleRate: number) => {
    // Flatten chunks
    const totalLength = chunks.reduce((acc, chunk) => acc + chunk.length / 2, 0);
    const floatData = new Float32Array(totalLength);
    let floatOffset = 0;

    chunks.forEach(chunk => {
      const int16 = new Int16Array(chunk.buffer);
      for (let i = 0; i < int16.length; i++) {
        floatData[floatOffset++] = int16[i] / 32768.0;
      }
    });

    const buffer = new ArrayBuffer(44 + floatData.length * 2);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) {
        v.setUint8(offset + i, string.charCodeAt(i));
      }
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 32 + floatData.length * 2, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, floatData.length * 2, true);
    let offset = 44;
    for (let i = 0; i < floatData.length; i++, offset += 2) {
      const s = Math.max(-1, Math.min(1, floatData[i]));
      view.setInt16(offset, s < 0 ? s * 0x8000 : s * 0x7FFF, true);
    }
    return buffer;
  };

  const stopConversation = () => {
    if (sessionRef.current) {
      sessionRef.current.close();
      sessionRef.current = null;
    }
    setActive(false);
  };

  const finalizeTurn = (transcript: string, chunks: Uint8Array[]) => {
    if (!transcript && chunks.length === 0) return;

    let audioUrl = null;
    if (chunks.length > 0) {
      const wav = encodeWAV(chunks, 24000);
      const blob = new Blob([wav], { type: 'audio/wav' });
      audioUrl = URL.createObjectURL(blob);
    }

    const newResponse: ResponseHistory = {
      id: Math.random().toString(36).substr(2, 9),
      transcript: transcript || '(Audio response)',
      audioUrl,
      timestamp: new Date()
    };

    setResponses(prev => [newResponse, ...prev]);
    setCurrentTurnAudioChunks([]);
    setCurrentOutputTranscription('');
  };

  const startConversation = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    const outputNode = audioContextRef.current.createGain();
    outputNode.connect(audioContextRef.current.destination);

    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

    const sessionPromise = ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      callbacks: {
        onopen: () => {
          setActive(true);
          const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
          const source = inputCtx.createMediaStreamSource(stream);
          const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

          scriptProcessor.onaudioprocess = (e) => {
            const inputData = e.inputBuffer.getChannelData(0);
            const int16 = new Int16Array(inputData.length);
            for (let i = 0; i < inputData.length; i++) {
                int16[i] = inputData[i] * 32768;
            }
            const pcmBlob = {
              data: encode(new Uint8Array(int16.buffer)),
              mimeType: 'audio/pcm;rate=16000',
            };
            sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
          };
          source.connect(scriptProcessor);
          scriptProcessor.connect(inputCtx.destination);
        },
        onmessage: async (message) => {
          if (message.serverContent?.outputTranscription) {
            setCurrentOutputTranscription(prev => prev + message.serverContent?.outputTranscription?.text);
          }

          if (message.serverContent?.turnComplete) {
            // Need to capture current state at completion. 
            // In a real state-heavy React app, we might use refs for chunks to avoid staleness.
          }

          const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
          if (audioData && audioContextRef.current) {
            const bytes = decode(audioData);
            // Collect for history
            setCurrentTurnAudioChunks(prev => [...prev, bytes]);

            const buffer = await decodeAudioData(bytes, audioContextRef.current, 24000, 1);
            const source = audioContextRef.current.createBufferSource();
            source.buffer = buffer;
            source.connect(outputNode);

            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, audioContextRef.current.currentTime);
            source.start(nextStartTimeRef.current);
            nextStartTimeRef.current += buffer.duration;
            sourcesRef.current.add(source);
            source.onended = () => sourcesRef.current.delete(source);
          }

          if (message.serverContent?.interrupted) {
            sourcesRef.current.forEach(s => s.stop());
            sourcesRef.current.clear();
            nextStartTimeRef.current = 0;
            // Interruption might need clearing currentTurn too
          }
        },
        onerror: (e) => {
          console.error(e);
          setActive(false);
        },
        onclose: () => setActive(false),
      },
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
        },
        outputAudioTranscription: {},
        inputAudioTranscription: {},
        systemInstruction: "You are a highly capable AI assistant in a low-latency voice environment. Be concise and conversational."
      }
    });

    sessionRef.current = await sessionPromise;
  };

  // Sync turn completion with finalizing the response object
  useEffect(() => {
    // This is a simple heuristic: if we have transcription/chunks and the model stops sending data,
    // we could finalize. For now, let's add a "Capture" button or use turnComplete logic.
    // Real-time turn management in React can be tricky; let's finalize on a small timeout of inactivity or user speaking.
  }, [currentOutputTranscription, currentTurnAudioChunks]);

  return (
    <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8 h-[calc(100vh-160px)] animate-in fade-in slide-in-from-bottom-4 duration-500">

      {/* Live Stream Section */}
      <div className="glass-panel rounded-3xl border-white/5 p-8 flex flex-col items-center justify-center relative overflow-hidden bg-gradient-to-b from-indigo-500/5 to-transparent">
        <div className={`w-56 h-56 rounded-full border-4 flex items-center justify-center transition-all duration-700 ${active ? 'border-indigo-500 shadow-[0_0_60px_rgba(99,102,241,0.4)] scale-110' : 'border-white/10 grayscale opacity-30'}`}>
           <div className={`w-40 h-40 rounded-full accent-gradient ${active ? 'animate-pulse' : ''} flex items-center justify-center shadow-inner`}>
              <svg className="w-20 h-20 text-white drop-shadow-lg" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
           </div>
        </div>

        <div className="mt-12 text-center space-y-4">
          <h3 className="text-3xl font-bold font-outfit">{active ? 'Assistant Listening' : 'System Ready'}</h3>
          <p className="text-gray-400 max-w-sm mx-auto">Engage in natural, low-latency conversation. Your interactions are recorded below for playback and download.</p>
        </div>

        <div className="mt-12 flex gap-4">
            <button
                onClick={active ? stopConversation : startConversation}
                className={`px-12 py-4 rounded-2xl font-bold transition-all shadow-xl flex items-center gap-3 ${active ? 'bg-red-500/20 border border-red-500/50 text-red-400 hover:bg-red-500/30' : 'accent-gradient text-white hover:scale-105'}`}
            >
                {active ? (
                  <><div className="w-3 h-3 bg-red-500 rounded-full animate-ping" /> End Session</>
                ) : 'Initiate Live Link'}
            </button>
            {active && (
               <button 
                onClick={() => finalizeTurn(currentOutputTranscription, currentTurnAudioChunks)}
                className="px-6 py-4 bg-white/5 border border-white/10 rounded-2xl font-bold hover:bg-white/10 transition-all text-indigo-300"
               >
                 Capture Response
               </button>
            )}
        </div>
      </div>

      {/* History & Controls Section */}
      <div className="flex flex-col space-y-6">
        <div className="flex items-center justify-between">
          <h4 className="text-sm font-bold text-gray-400 uppercase tracking-widest">Interaction History</h4>
          <span className="text-xs text-gray-500">{responses.length} responses recorded</span>
        </div>

        <div className="flex-1 glass-panel rounded-3xl border-white/5 overflow-y-auto p-6 space-y-4 custom-scrollbar">
          {responses.length === 0 && (
            <div className="h-full flex flex-col items-center justify-center opacity-20 text-center p-12 space-y-4">
               <svg className="w-16 h-16" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
               <p className="font-medium">Responses will appear here as the conversation progresses.</p>
            </div>
          )}

          {responses.map((resp) => (
            <div key={resp.id} className="p-5 bg-white/5 border border-white/10 rounded-2xl space-y-4 animate-in slide-in-from-right-4">
              <div className="flex items-start justify-between gap-4">
                <p className="text-gray-300 text-sm leading-relaxed flex-1">{resp.transcript}</p>
                <span className="text-[10px] text-gray-600 shrink-0 uppercase font-bold">{resp.timestamp.toLocaleTimeString()}</span>
              </div>

              {resp.audioUrl && (
                <div className="flex items-center gap-4 p-3 bg-black/20 rounded-xl">
                  <audio src={resp.audioUrl} controls className="flex-1 h-8" />
                  <a 
                    href={resp.audioUrl} 
                    download={`response-${resp.id}.wav`}
                    className="p-2 text-indigo-400 hover:text-indigo-300 transition-colors"
                    title="Download Audio"
                  >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                  </a>
                </div>
              )}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

