            <div className="p-8 glass-panel rounded-3xl border-indigo-500/30 flex flex-col gap-6 animate-in slide-in-from-top-4 shadow-2xl bg-indigo-500/5">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 rounded-full bg-indigo-500/20 flex items-center justify-center text-indigo-400 animate-pulse">
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19V6l12-3v13M9 19c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zm12-3c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zM9 10l12-3" /></svg>
                  </div>
                  <div>
                    <h4 className="font-bold text-white">Generated Synthesis</h4>
                    <p className="text-xs text-gray-400">Speaker: {selectedVoice.name}</p>
