import { GoogleGenAI, Modality, Type, GenerateContentResponse } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateTTS = async (text: string, voiceName: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName },
        },
      },
    },
  });
  return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
};

export const classifyVoice = async (base64Audio: string, mimeType: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            data: base64Audio.split(',')[1],
            mimeType
          }
        },
        {
          text: "Analyze the vocal characteristics of this speaker. Identify if the voice is masculine, feminine, or neutral. Based on the pitch and tone, select the BEST match from these pre-built voice IDs: 'Puck' (Masculine/Energetic), 'Charon' (Masculine/Deep), 'Zephyr' (Masculine/Neutral), 'Kore' (Feminine/Calm), 'Aoide' (Feminine/Bright). Return ONLY the voice ID string."
        }
      ]
    }
  });

  const text = response.text?.trim() || 'Zephyr';
  // Fallback cleanup to ensure it only returns a valid ID
  const validVoices = ['Puck', 'Charon', 'Zephyr', 'Kore', 'Aoide', 'Fenrir'];
  const matched = validVoices.find(v => text.includes(v));
  return matched || 'Zephyr';
};

export const generateVideo = async (prompt: string, aspectRatio: '16:9' | '9:16', startImage?: string) => {
  const ai = getAI();
  const payload: any = {
    model: 'veo-3.1-fast-generate-preview',
    prompt,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio
    }
  };

  if (startImage) {
    payload.image = {
      imageBytes: startImage.split(',')[1],
      mimeType: 'image/png'
    };
  }

  let operation = await ai.models.generateVideos(payload);

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await response.blob();
  return URL.createObjectURL(blob);
};

export const generateImage = async (prompt: string, size: '1K' | '2K' | '4K') => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts: [{ text: prompt }] },
    config: {
      imageConfig: {
        aspectRatio: "1:1",
        imageSize: size
      }
    },
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return null;
};

export const analyzeMedia = async (fileBase64: string, mimeType: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        {
          inlineData: {
            data: fileBase64.split(',')[1],
            mimeType
          }
        },
        {
          text: "Provide a complete verbatim transcript of the audio content, followed by a professional summary of the key themes, actions, or information presented."
        }
      ]
    },
    config: {
        responseMimeType: "application/json",
        responseSchema: {
            type: Type.OBJECT,
            properties: {
                transcript: { type: Type.STRING },
                summary: { type: Type.STRING }
            },
            required: ["transcript", "summary"]
        }
    }
  });

  try {
    return JSON.parse(response.text || '{}');
  } catch (e) {
    return { transcript: response.text, summary: "Could not parse JSON response" };
  }
};

import React, { useState, useRef } from 'react';
import { ELEVEN_LABS_VOICES, VoiceProfile } from '../types';
import { generateTTS, classifyVoice } from '../services/geminiService';

const TTSView: React.FC = () => {
  const [text, setText] = useState('');
  const [selectedVoice, setSelectedVoice] = useState<VoiceProfile>(ELEVEN_LABS_VOICES[0]);
  const [loading, setLoading] = useState(false);
  const [cloning, setCloning] = useState(false);
  const [cloningStatus, setCloningStatus] = useState('');
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [clonedVoices, setClonedVoices] = useState<VoiceProfile[]>(ELEVEN_LABS_VOICES);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const encodeWAV = (samples: Float32Array, sampleRate: number) => {
    const buffer = new ArrayBuffer(44 + samples.length * 2);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) {
        v.setUint8(offset + i, string.charCodeAt(i));
      }
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 32 + samples.length * 2, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, samples.length * 2, true);
    let offset = 44;
    for (let i = 0; i < samples.length; i++, offset += 2) {
      const s = Math.max(-1, Math.min(1, samples[i]));
      view.setInt16(offset, s < 0 ? s * 0x8000 : s * 0x7FFF, true);
    }
    return buffer;
  };

  const handleGenerate = async () => {
    if (!text) return;
    setLoading(true);
    try {
      const base64Audio = await generateTTS(text, selectedVoice.geminiVoice);
      if (base64Audio) {
        const binaryString = atob(base64Audio);
        const bytes = new Uint8Array(binaryString.length);
        const int16Data = new Int16Array(bytes.buffer);
        for (let i = 0; i < binaryString.length; i++) {
          bytes[i] = binaryString.charCodeAt(i);
        }

        const floatData = new Float32Array(int16Data.length);
        for (let i = 0; i < int16Data.length; i++) {
          floatData[i] = int16Data[i] / 32768.0;
        }

        const wavBuffer = encodeWAV(floatData, 24000);
        const blob = new Blob([wavBuffer], { type: 'audio/wav' });
        const url = URL.createObjectURL(blob);
        setAudioUrl(url);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleCloneVoice = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setCloning(true);
    setCloningStatus('Uploading sample...');

    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = reader.result as string;
        setCloningStatus('Analyzing vocal characteristics...');

        // Real analysis using Gemini to determine the best matching engine
        const matchedVoiceId = await classifyVoice(base64, file.type);

        setCloningStatus(`Matching to ${matchedVoiceId} profile...`);

        const newVoice: VoiceProfile = {
          id: Math.random().toString(36).substr(2, 20),
          name: `Cloned ${file.name.split('.')[0]}`,
          geminiVoice: matchedVoiceId
        };

        setClonedVoices([newVoice, ...clonedVoices]);
        setSelectedVoice(newVoice);
        setCloning(false);
        setCloningStatus('');
        if (fileInputRef.current) fileInputRef.current.value = '';
      };
      reader.readAsDataURL(file);
    } catch (error) {
      console.error("Cloning failed", error);
      setCloning(false);
      setCloningStatus('Cloning failed. Try a clearer sample.');
    }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20">
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Input and Results */}
        <div className="lg:col-span-8 space-y-6">
          <div className="space-y-2">
            <label className="text-sm font-bold text-gray-400 uppercase tracking-widest flex justify-between">
              Synthesis Text
              <span className="text-indigo-400">{text.length} characters</span>
            </label>
            <textarea
              value={text}
              onChange={(e) => setText(e.target.value)}
              placeholder="Type or paste the script you want to transform into audio..."
              className="w-full h-80 p-8 glass-panel rounded-3xl border-white/10 focus:border-indigo-500/50 focus:ring-2 focus:ring-indigo-500/20 outline-none resize-none transition-all text-lg leading-relaxed shadow-2xl"
            />
          </div>

          <button
            onClick={handleGenerate}
            disabled={loading || !text}
            className={`w-full py-5 accent-gradient rounded-2xl font-bold flex items-center justify-center gap-3 transition-all text-xl ${loading ? 'opacity-50 cursor-not-allowed' : 'hover:shadow-[0_0_30px_rgba(99,102,241,0.4)] hover:scale-[1.01] active:scale-[0.99]'}`}
          >
            {loading ? (
              <><div className="w-6 h-6 border-3 border-white/30 border-t-white rounded-full animate-spin" /> Generating Audio Master...</>
            ) : (
              <><svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg> Synthesis Speech</>
            )}
          </button>

          {audioUrl && (
            <div className="p-8 glass-panel rounded-3xl border-indigo-500/30 flex flex-col gap-6 animate-in slide-in-from-top-4 shadow-2xl bg-indigo-500/5">
