import React, { useState } from 'react';
import { analyzeMedia, analyzeUrl } from '../services/geminiService';
import { AnalysisResult } from '../types';

interface SequencedSegment {
  type: string;
  timestamp?: string;
  text: string;
}

interface EnhancedAnalysisResult extends AnalysisResult {
  sequencedScript?: SequencedSegment[];
}

const MediaAnalysisView: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [urlInput, setUrlInput] = useState('');
  const [preview, setPreview] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<EnhancedAnalysisResult | null>(null);
  const [activeTab, setActiveTab] = useState<'upload' | 'url'>('upload');

  const handleFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const f = e.target.files?.[0];
    if (f) {
      setFile(f);
      const url = URL.createObjectURL(f);
      setPreview(url);
      setResult(null);
      setUrlInput('');
    }
  };

  const downloadScript = () => {
    if (!result) return;
    let content = `GEMINI MULTIMODAL STUDIO - ANALYSIS REPORT\n\nEXECUTIVE SUMMARY:\n${result.summary}\n\n`;

    if (result.sequencedScript && result.sequencedScript.length > 0) {
      content += `SEQUENCED SCRIPT:\n`;
      result.sequencedScript.forEach(s => {
        content += `[${s.type.toUpperCase()}] ${s.timestamp ? `(${s.timestamp})` : ''}\n${s.text}\n\n`;
      });
    }

    content += `\nFULL VERBATIM TRANSCRIPT:\n${result.transcript}`;

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `sequenced-script-${new Date().getTime()}.txt`;
    a.click();
  };

  const processUpload = async () => {
    if (!file) return;
    setLoading(true);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = reader.result as string;
        const analysis = await analyzeMedia(base64, file.type);
        setResult(analysis);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const processUrl = async () => {
    if (!urlInput) return;
    setLoading(true);
    try {
      const analysis = await analyzeUrl(urlInput);
      setResult(analysis);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20">
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Left: Inputs */}
