              {loading && <div className="w-5 h-5 border-2 border-indigo-500/30 border-t-indigo-500 rounded-full animate-spin"></div>}
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar min-h-[500px]">
              {!result && !loading && (
                <div className="h-full flex flex-col items-center justify-center opacity-20 text-center space-y-6 py-20">
                  <div className="w-24 h-24 rounded-full border border-white/10 flex items-center justify-center text-5xl">📜</div>
                  <div className="space-y-2">
                    <p className="text-2xl font-bold font-outfit">Waiting for Input</p>
                    <p className="text-sm max-w-xs">Upload a video or provide a URL to get the full Hook, Intro, and script breakdown.</p>
                  </div>
                </div>
              )}

              {loading && (
                <div className="h-full flex flex-col items-center justify-center space-y-6 py-20">
                  <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                  <p className="text-indigo-400 font-bold animate-pulse">Neural Engine Mapping Sequences...</p>
                </div>
              )}

              {result && (
                <div className="space-y-6">
                  {result.sequencedScript && result.sequencedScript.length > 0 ? (
                    result.sequencedScript.map((segment, idx) => (
                      <div key={idx} className="relative pl-10 group">
                        {/* Vertical line */}
                        {idx !== result.sequencedScript!.length - 1 && (
                          <div className="absolute left-[19px] top-10 bottom-[-24px] w-0.5 bg-white/5 group-hover:bg-indigo-500/20 transition-colors"></div>
