import { GoogleGenAI, Modality, Type, GenerateContentResponse } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export class QuotaError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "QuotaError";
  }
}

export class PermissionError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "PermissionError";
  }
}

const handleApiError = (error: any) => {
  console.error("API Error Details:", error);
  const errorMessage = error?.message || String(error);

  if (errorMessage.includes("429") || errorMessage.toLowerCase().includes("quota exceeded") || errorMessage.toLowerCase().includes("too many requests")) {
    throw new QuotaError("The current API key has exceeded its quota limit.");
  }

  if (errorMessage.includes("403") || errorMessage.toLowerCase().includes("permission denied") || errorMessage.toLowerCase().includes("caller does not have permission")) {
    throw new PermissionError("Permission Denied: Ensure your project has billing enabled and the requested model (e.g., Veo) is active.");
  }

  throw error;
};

export const generateTTS = async (text: string, voiceName: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (e) {
    return handleApiError(e);
  }
};

export const classifyVoice = async (base64Audio: string, mimeType: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Audio.split(',')[1],
              mimeType
            }
          },
          {
            text: "Analyze the vocal characteristics of this speaker. Identify if the voice is masculine, feminine, or neutral. Based on the pitch and tone, select the BEST match from these pre-built voice IDs: 'Puck' (Masculine/Energetic), 'Charon' (Masculine/Deep), 'Zephyr' (Masculine/Neutral), 'Kore' (Feminine/Calm), 'Aoide' (Feminine/Bright). Return ONLY the voice ID string."
          }
        ]
      }
    });

    const text = response.text?.trim() || 'Zephyr';
    const validVoices = ['Puck', 'Charon', 'Zephyr', 'Kore', 'Aoide', 'Fenrir'];
    const matched = validVoices.find(v => text.includes(v));
    return matched || 'Zephyr';
  } catch (e) {
    return handleApiError(e);
  }
};

export const generateVideo = async (prompt: string, aspectRatio: '16:9' | '9:16', startImage?: string) => {
  try {
    const ai = getAI();
    const payload: any = {
      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt || 'A cinematic cinematic scene',
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio
      }
    };

    if (startImage) {
      payload.image = {
        imageBytes: startImage.split(',')[1],
        mimeType: 'image/png'
      };
    }

    let operation = await ai.models.generateVideos(payload);

    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    if (!response.ok) throw new Error(`Video fetch failed: ${response.status}`);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
  } catch (e) {
    return handleApiError(e);
  }
};

export const generateImage = async (prompt: string, size: '1K' | '2K' | '4K') => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: size
        }
      },
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (e) {
    return handleApiError(e);
  }
};

export const analyzeMedia = async (fileBase64: string, mimeType: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          {
            inlineData: {
              data: fileBase64.split(',')[1],
              mimeType
            }
          },
          {
            text: "Provide a complete verbatim transcript. Then, analyze the content and return a JSON object with the transcript, a summary, and a 'sequencedScript' which is an array of objects. Each object in sequencedScript must have 'type' (Hook, Intro, Body Segment, Outro), 'timestamp' (estimated), and 'text'."
          }
        ]
      },
      config: {
          responseMimeType: "application/json",
          responseSchema: {
              type: Type.OBJECT,
              properties: {
                  transcript: { type: Type.STRING },
                  summary: { type: Type.STRING },
                  sequencedScript: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        type: { type: Type.STRING },
                        timestamp: { type: Type.STRING },
                        text: { type: Type.STRING }
                      },
                      required: ["type", "text"]
                    }
                  }
              },
              required: ["transcript", "summary", "sequencedScript"]
          }
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (e) {
    return handleApiError(e);
  }
};

export const analyzeUrl = async (url: string) => {
  try {
    const ai = getAI();
    // Using gemini-3-flash-preview for search grounding as it's generally more robust for this tool.
    // We avoid JSON mode when using googleSearch as guidelines suggest text response might not be JSON.
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze the video content at this URL: ${url}. Find the transcript and structure it into a sequence including Hook, Intro, Body Segments, and Outro. Return the result in a clear structured text format.`,
      config: {
        tools: [{ googleSearch: {} }],
      }
    });

    const text = response.text || '';
    // Since we are not in JSON mode, we'll return a structured summary.
    return { 
      transcript: text, 
      summary: "Analysis complete via Search Grounding.", 
      sequencedScript: [{ type: "Analysis", text: text }],
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (e) {
    return handleApiError(e);
  }
};

