import { GoogleGenAI, Modality, Type, GenerateContentResponse } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export class QuotaError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "QuotaError";
  }
}

export class PermissionError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "PermissionError";
  }
}

const handleApiError = (error: any) => {
  console.error("API Error Details:", error);
  const errorMessage = error?.message || String(error);

  if (errorMessage.includes("429") || errorMessage.toLowerCase().includes("quota exceeded") || errorMessage.toLowerCase().includes("too many requests")) {
    throw new QuotaError("The current API key has exceeded its quota limit.");
  }

  if (errorMessage.includes("403") || errorMessage.toLowerCase().includes("permission denied") || errorMessage.toLowerCase().includes("caller does not have permission")) {
    throw new PermissionError("Permission Denied: Ensure project billing is active.");
  }

  throw error;
};

/**
 * Enhance Voice V3: Prosody optimization layer.
 */
export const enhanceTextForSpeech = async (text: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `You are an elite speech synthesis engineer. Rewrite the following text to optimize it for an ultra-realistic "V3" neural voice. 
      Add prosody cues: 
      - Use "..." for natural pauses.
      - Use ALL CAPS for emphasized words.
      - Use punctuation to control tone.

      Original Text: "${text}"

      Return ONLY the optimized synthesis script.`,
    });
    return response.text || text;
  } catch (e) {
    console.warn("Speech enhancement layer failed", e);
    return text;
  }
};

/**
 * Visual Backdrop Engine: Summarizes text into an image prompt.
 */
export const summarizeForVisuals = async (text: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Create a cinematic 1:1 image prompt that visually represents the core theme of this speech script. Focus on lighting, high-quality textures, and mood. Under 50 words. 

      Script: "${text}"`,
    });
    return response.text || "A cinematic atmospheric professional studio backdrop";
  } catch (e) {
    return "A cinematic atmospheric professional studio backdrop";
  }
};

export const generateTTS = async (text: string, voiceName: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (e) {
    return handleApiError(e);
  }
};

/**
 * Precise Voice Classification: Strict gender-matching logic.
 */
export const classifyVoice = async (base64Audio: string, mimeType: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Audio.split(',')[1],
              mimeType
            }
          },
          {
            text: "Analyze this voice sample with 100% precision. 1) Determine the gender (Male/Female). 2) Map it to the most accurate Gemini Prebuilt ID: 'Puck' (Male energetic), 'Charon' (Male deep), 'Zephyr' (Male neutral), 'Kore' (Female calm), 'Aoide' (Female bright), 'Fenrir' (Male/Neutral deep/gravelly). YOU MUST NOT CHANGE THE GENDER. Return ONLY the Gemini ID."
          }
        ]
      }
    });
    const text = response.text?.trim() || 'Zephyr';
    const validVoices = ['Puck', 'Charon', 'Zephyr', 'Kore', 'Aoide', 'Fenrir'];
    return validVoices.find(v => text.includes(v)) || 'Zephyr';
  } catch (e) {
    return handleApiError(e);
  }
};

export const generateVideo = async (prompt: string, aspectRatio: '16:9' | '9:16', startImage?: string) => {
  try {
    const ai = getAI();
    const payload: any = {
      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt || 'A cinematic scene',
      config: { numberOfVideos: 1, resolution: '720p', aspectRatio }
    };
    if (startImage) payload.image = { imageBytes: startImage.split(',')[1], mimeType: 'image/png' };
    let operation = await ai.models.generateVideos(payload);
    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }
    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
  } catch (e) {
    return handleApiError(e);
  }
};

export const generateImage = async (prompt: string, size: '1K' | '2K' | '4K', useNanoPro: boolean = false) => {
  try {
    const ai = getAI();
    const model = (useNanoPro || size !== '1K') ? 'gemini-3-pro-image-preview' : 'gemini-2.5-flash-image';
    const imageConfig: any = { aspectRatio: "1:1" };
    if (model === 'gemini-3-pro-image-preview') imageConfig.imageSize = size;
    const response = await ai.models.generateContent({
      model,
      contents: { parts: [{ text: prompt }] },
      config: { imageConfig },
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    return null;
  } catch (e) {
    return handleApiError(e);
  }
};

export const analyzeMedia = async (fileBase64: string, mimeType: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { data: fileBase64.split(',')[1], mimeType } },
          { text: "Provide transcript and summary JSON." }
        ]
      },
      config: {
          responseMimeType: "application/json",
          responseSchema: {
              type: Type.OBJECT,
              properties: {
                  transcript: { type: Type.STRING },
                  summary: { type: Type.STRING },
                  sequencedScript: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        type: { type: Type.STRING },
                        text: { type: Type.STRING }
                      },
                      required: ["type", "text"]
                    }
                  }
              },
              required: ["transcript", "summary", "sequencedScript"]
          }
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (e) {
    return handleApiError(e);
  }
};

export const analyzeUrl = async (url: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze URL: ${url}.`,
      config: { tools: [{ googleSearch: {} }] }
    });
    const text = response.text || '';
    return { 
      transcript: text, 
      summary: "Analysis complete.", 
      sequencedScript: [{ type: "Analysis", text: text }],
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (e) {
    return handleApiError(e);
  }
};

import React, { useState, useRef } from 'react';
import { ELEVEN_LABS_VOICES, VoiceProfile } from '../types';
import { generateTTS, classifyVoice, enhanceTextForSpeech, summarizeForVisuals, generateImage } from '../services/geminiService';

const TTSView: React.FC = () => {
  const [text, setText] = useState('');
  const [selectedVoice, setSelectedVoice] = useState<VoiceProfile>(ELEVEN_LABS_VOICES[0]);
  const [loading, setLoading] = useState(false);
  const [cloning, setCloning] = useState(false);
  const [cloningStatus, setCloningStatus] = useState('');
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [visualUrl, setVisualUrl] = useState<string | null>(null);
  const [shouldEnhance, setShouldEnhance] = useState(true);
  const [shouldGenerateVisual, setShouldGenerateVisual] = useState(true);
  const [clonedVoices, setClonedVoices] = useState<VoiceProfile[]>(ELEVEN_LABS_VOICES);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const encodeWAV = (samples: Float32Array, sampleRate: number) => {
    const buffer = new ArrayBuffer(44 + samples.length * 2);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) v.setUint8(offset + i, string.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 32 + samples.length * 2, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, samples.length * 2, true);
    let offset = 44;
    for (let i = 0; i < samples.length; i++, offset += 2) {
      const s = Math.max(-1, Math.min(1, samples[i]));
      view.setInt16(offset, s < 0 ? s * 0x8000 : s * 0x7FFF, true);
    }
    return buffer;
  };

  const handleGenerate = async () => {
    if (!text) return;
    setLoading(true);
    setAudioUrl(null);
    setVisualUrl(null);

    try {
      let processingText = text;

      // Feature: Neural Enhancement V3 (Alpha Prosody Engine)
      if (shouldEnhance) {
        processingText = await enhanceTextForSpeech(text);
      }

      // Concurrently synthesize audio and generate visual (only if allowed)
      const synthesisPromise = generateTTS(processingText, selectedVoice.geminiVoice);

      let visualPromise = Promise.resolve(null as string | null);
      if (shouldGenerateVisual) {
        // Fast visual generation using Flash Image (Nano Banana)
        visualPromise = summarizeForVisuals(text).then(prompt => generateImage(prompt, '1K', false));
      }

      const [base64Audio, imageResult] = await Promise.all([synthesisPromise, visualPromise]);

      if (base64Audio) {
        const binaryString = atob(base64Audio);
        const bytes = new Uint8Array(binaryString.length);
        const int16Data = new Int16Array(bytes.buffer);
        for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
        const floatData = new Float32Array(int16Data.length);
        for (let i = 0; i < int16Data.length; i++) floatData[i] = int16Data[i] / 32768.0;
        const wavBuffer = encodeWAV(floatData, 24000);
        setAudioUrl(URL.createObjectURL(new Blob([wavBuffer], { type: 'audio/wav' })));
      }

      if (imageResult) {
        setVisualUrl(imageResult);
      }

    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleCloneVoice = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setCloning(true);
    setCloningStatus('Analyzing Identity...');
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = reader.result as string;
        const matchedVoiceId = await classifyVoice(base64, file.type);

        // Strict mapping based on ID to ensure gender persistence
        const maleIDs = ['Puck', 'Charon', 'Zephyr', 'Fenrir'];
        const isMale = maleIDs.includes(matchedVoiceId);

        const newVoice: VoiceProfile = {
          id: Math.random().toString(36).substr(2, 9),
          name: `Neural ${file.name.split('.')[0]}`,
          geminiVoice: matchedVoiceId,
          description: `High-fidelity custom clone (${isMale ? 'Male' : 'Female'})`,
          gender: isMale ? 'male' : 'female'
        };
        setClonedVoices([newVoice, ...clonedVoices]);
        setSelectedVoice(newVoice);
        setCloning(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      };
      reader.readAsDataURL(file);
    } catch (error) {
      console.error("Cloning Error:", error);
      setCloning(false);
    }
  };

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20">
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Main Interface */}
        <div className="lg:col-span-8 space-y-6">
          <div className="space-y-4">
            <div className="flex items-center justify-between px-1">
              <label className="text-sm font-bold text-gray-400 uppercase tracking-widest">Synthesis Script</label>
              <div className="flex gap-4">
                 <button 
                  onClick={() => setShouldEnhance(!shouldEnhance)}
                  className={`flex items-center gap-2 text-[10px] font-bold px-3 py-1.5 rounded-full border transition-all ${shouldEnhance ? 'bg-indigo-500/20 border-indigo-500 text-indigo-400' : 'bg-white/5 border-white/10 text-gray-500'}`}
                 >
                   <div className={`w-1.5 h-1.5 rounded-full ${shouldEnhance ? 'bg-indigo-500 animate-pulse' : 'bg-gray-600'}`}></div>
                   ENHANCE V3 (ALPHA)
                 </button>
                 <button 
                  onClick={() => setShouldGenerateVisual(!shouldGenerateVisual)}
                  className={`flex items-center gap-2 text-[10px] font-bold px-3 py-1.5 rounded-full border transition-all ${shouldGenerateVisual ? 'bg-emerald-500/20 border-emerald-500 text-emerald-400' : 'bg-white/5 border-white/10 text-gray-500'}`}
                 >
                   <div className={`w-1.5 h-1.5 rounded-full ${shouldGenerateVisual ? 'bg-emerald-500 animate-pulse' : 'bg-gray-600'}`}></div>
                   SYNC VISUAL FORGE
                 </button>
              </div>
            </div>
            <textarea
              value={text}
              onChange={(e) => setText(e.target.value)}
              placeholder="Enter your script here. Turn on Sync Visual Forge to generate images automatically..."
              className="w-full h-80 p-8 glass-panel rounded-3xl border-white/10 focus:border-indigo-500/50 outline-none resize-none transition-all text-lg leading-relaxed shadow-2xl"
            />
          </div>

          <button
            onClick={handleGenerate}
            disabled={loading || !text}
            className={`w-full py-6 accent-gradient rounded-2xl font-bold flex items-center justify-center gap-3 transition-all text-xl ${loading ? 'opacity-50 cursor-wait' : 'hover:shadow-2xl hover:scale-[1.01]'}`}
          >
            {loading ? (
              <><div className="w-6 h-6 border-3 border-white/30 border-t-white rounded-full animate-spin" /> Neural Syncing...</>
            ) : (
              <><svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg> Master Synthesis</>
            )}
          </button>

          {(audioUrl || visualUrl) && (
            <div className="grid grid-cols-1 md:grid-cols-12 gap-8 animate-in slide-in-from-top-6">
              {visualUrl && (
                <div className="md:col-span-5 aspect-square glass-panel rounded-3xl border-emerald-500/20 overflow-hidden shadow-2xl group relative">
                  <img src={visualUrl} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" alt="Visual Backdrop" />
                  <div className="absolute top-4 left-4 bg-emerald-500/30 backdrop-blur-md px-3 py-1 rounded-full border border-emerald-500/50 text-[10px] font-bold text-emerald-400">SYNCED VISUAL</div>
                </div>
              )}
              <div className={`${visualUrl ? 'md:col-span-7' : 'md:col-span-12'} p-8 glass-panel rounded-3xl border-indigo-500/30 flex flex-col justify-between shadow-2xl bg-indigo-500/5`}>
                <div className="space-y-6">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-4">
                      <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-bold text-xl ${selectedVoice.gender === 'female' ? 'bg-pink-500/20 text-pink-400' : 'bg-blue-500/20 text-blue-400'}`}>
                        {selectedVoice.name.charAt(0)}
                      </div>
                      <div>
                        <h4 className="font-bold text-white text-lg">{selectedVoice.name}</h4>
                        <p className="text-xs text-gray-400">{selectedVoice.description} • Enhanced V3</p>
                      </div>
                    </div>
                    {audioUrl && (
                      <a href={audioUrl} download={`${selectedVoice.name}-output.wav`} className="p-4 bg-indigo-500 rounded-2xl hover:bg-indigo-600 transition-all text-white shadow-xl shadow-indigo-500/30">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                      </a>
                    )}
                  </div>

                  <div className="bg-black/40 p-5 rounded-2xl border border-white/5">
                    <div className="flex items-center gap-2 mb-4">
