/**
 * Generate Neural Speech
 * Optimized to handle pure script strings and avoid text-only response errors.
 */
export const generateTTS = async (text: string, voiceName: string) => {
  if (!text || text.trim().length === 0) return null;

  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text.trim() }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const audioPart = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
    if (!audioPart) {
      console.warn("Model returned non-audio response for TTS. Checking text output:", response.text);
      // Fallback: If it returns text, retry with a cleaner prompt once
      return null;
    }

    return audioPart.inlineData.data;
  } catch (e) {
    return handleApiError(e);
  }
};

