/**
 * Generate Neural Speech
 * Optimized to handle pure script strings and avoid 'non-audio response' errors.
 */
export const generateTTS = async (text: string, voiceName: string) => {
  const sanitizedText = text?.trim();
  // The TTS model requires actual speakable content. Symbol-only or empty prompts trigger 400 errors.
  if (!sanitizedText || sanitizedText.length < 2 || !/[a-zA-Z0-9]/.test(sanitizedText)) {
    console.warn("TTS skipped: Input text is insufficient for synthesis.");
    return null;
  }

  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: sanitizedText }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const audioPart = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);

    if (!audioPart) {
      // Logic for handling the specific 400 error where model returns text instead of audio modality
      const refusalText = response.text;
      console.error("TTS Refusal: Model returned non-audio response.", refusalText);
      throw new Error(`The neural engine refused this specific script. Try rephrasing.`);
    }

    return audioPart.inlineData.data;
  } catch (e) {
    return handleApiError(e);
  }
};

/**
 * Precise Voice Classification: Rigid gender-matching logic.
 * Prevents unintended gender swaps during the cloning process.
 */
export const classifyVoice = async (base64Audio: string, mimeType: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Audio.split(',')[1],
              mimeType
            }
          },
          {
            text: `Analyze this voice sample. 

            1. First, determine the biological gender: MALE or FEMALE.
            2. Match to the best Gemini Voice ID based on that gender:
               - FEMALE: 'Kore' (Calm/Pro) or 'Aoide' (Bright/Lyrical)
               - MALE: 'Puck' (Energetic), 'Charon' (Deep), 'Zephyr' (Neutral), or 'Fenrir' (Gravelly)

            STRICT RULE: Do not switch gender. A female sample must stay female (Kore/Aoide). A male sample must stay male (Puck/Charon/Zephyr/Fenrir).

            Return ONLY the name of the matched ID.`
          }
        ]
      }
    });
    const text = response.text?.trim() || 'Zephyr';
    const validVoices = ['Puck', 'Charon', 'Zephyr', 'Kore', 'Aoide', 'Fenrir'];
    const matched = validVoices.find(v => text.includes(v));
    return matched || 'Zephyr';
  } catch (e) {
    return handleApiError(e);
  }
};

export const generateVideo = async (prompt: string, aspectRatio: '16:9' | '9:16', startImage?: string) => {
  try {
    const ai = getAI();
    const payload: any = {
      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt || 'A cinematic scene',
      config: { numberOfVideos: 1, resolution: '720p', aspectRatio }
    };
    if (startImage) payload.image = { imageBytes: startImage.split(',')[1], mimeType: 'image/png' };
    let operation = await ai.models.generateVideos(payload);
    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }
    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
  } catch (e) {
    return handleApiError(e);
  }
};

export const generateImage = async (prompt: string, size: '1K' | '2K' | '4K', useNanoPro: boolean = false) => {
  try {
    const ai = getAI();
    const model = (useNanoPro || size !== '1K') ? 'gemini-3-pro-image-preview' : 'gemini-2.5-flash-image';
    const imageConfig: any = { aspectRatio: "1:1" };
    if (model === 'gemini-3-pro-image-preview') imageConfig.imageSize = size;
    const response = await ai.models.generateContent({
      model,
      contents: { parts: [{ text: prompt }] },
      config: { imageConfig },
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    return null;
  } catch (e) {
    return handleApiError(e);
  }
};

