            <textarea
              value={text}
              onChange={(e) => { setText(e.target.value); if (errorMsg) setErrorMsg(null); }}
              placeholder="Paste your content here for high-fidelity synthesis..."
              className="w-full h-80 p-8 glass-panel rounded-3xl border-white/10 focus:border-indigo-500/50 outline-none resize-none transition-all text-lg leading-relaxed shadow-2xl font-light"
            />
          </div>

