}

export class PermissionError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "PermissionError";
  }
}

const handleApiError = (error: any) => {
  console.error("API Error Details:", error);
  const errorMessage = error?.message || String(error);

  if (errorMessage.includes("429") || errorMessage.toLowerCase().includes("quota exceeded") || errorMessage.toLowerCase().includes("too many requests")) {
    throw new QuotaError("The current API key has exceeded its quota limit.");
  }

  if (errorMessage.includes("403") || errorMessage.toLowerCase().includes("permission denied") || errorMessage.toLowerCase().includes("caller does not have permission")) {
    throw new PermissionError("Permission Denied: Ensure project billing is active.");
  }

  throw error;
};

/**
 * Enhance Voice V3 Alpha: Prosody optimization layer.
 * Strips conversational filler to prevent TTS refusal errors (the "Non-audio response" bug).
 */
export const enhanceTextForSpeech = async (text: string) => {
  if (!text || text.trim().length < 2) return text;
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `You are a Neural Synthesis Specialist. Optimize this script for a V3 TTS engine.

      CRITICAL OUTPUT RULES:
      - OUTPUT ONLY THE FINAL OPTIMIZED TEXT.
      - DO NOT INCLUDE intros like "Here is the script".
      - DO NOT INCLUDE markdown code blocks.
      - DO NOT INCLUDE any text that is not intended to be spoken.
      - IF the input is too short or weird, return the original text.

      INPUT SCRIPT: "${text}"`,
    });

    let cleaned = response.text?.trim() || text;
    // Aggressive cleaning to ensure no conversational meta-talk survives
    cleaned = cleaned.replace(/^(Optimized|Script|Speech|Neural output|Here is your script|The optimized script is):\s*/i, '');
    cleaned = cleaned.replace(/^[`"']+|[`"']+$/g, '').trim();

    return cleaned || text;
  } catch (e) {
    console.warn("Speech enhancement layer failed", e);
    return text;
  }
};

/**
 * Generate Neural Speech
 * Optimized to handle pure script strings and avoid 'non-audio response' errors.
 */
export const generateTTS = async (text: string, voiceName: string) => {
  const sanitizedText = text?.trim();

  // The TTS model requires actual speakable content. Symbol-only or empty prompts trigger 400 errors.
  if (!sanitizedText || sanitizedText.length < 2 || !/[a-zA-Z0-9]/.test(sanitizedText)) {
    console.warn("TTS skipped: Input text is insufficient for synthesis.");
    return null;
  }

  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: sanitizedText }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const audioPart = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);

    if (!audioPart) {
      // The 400 Error "non-audio response" happens here. We catch the text refusal and log it.
      const refusalText = response.text;
      console.error("TTS Refusal: Engine returned text instead of audio.", refusalText);
      throw new Error(`The Neural Engine refused to synthesize this script. This usually happens if the script contains meta-commands or blocked content.`);
    }

    return audioPart.inlineData.data;
  } catch (e) {
    return handleApiError(e);
  }
};

