/**
 * Clean text for TTS
 * Removes markdown, excessive symbols, and non-speakable characters.
 */
const sanitizeForTTS = (text: string): string => {
  return text
    .replace(/\*\*/g, '') // Remove bold
    .replace(/\*/g, '')  // Remove italic
    .replace(/#/g, '')   // Remove headers
    .replace(/[`]/g, '') // Remove backticks
    .replace(/_{2,}/g, '') // Remove long underscores
    .replace(/\[|\]|\(|\)/g, '') // Remove brackets
    .trim();
};

/**
 * Enhance Voice V3 Alpha: Prosody optimization layer.
 * Rigidly constrained to prevent "Non-audio response" refusal errors.
 */
export const enhanceTextForSpeech = async (text: string) => {
  if (!text || text.trim().length < 2) return text;
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `You are a professional Neural Speech Optimizer. Rewrite the script below for high-fidelity TTS.

      RULES:
      1. Use "..." for brief pauses.
      2. Use ALL CAPS for subtle emphasis.
      3. OUTPUT ONLY THE SCRIPT.
      4. NO markdown, NO code blocks, NO introductory text.
      5. If the script is potentially unsafe, return exactly: "REDACTED".

      Script: "${text}"`,
    });

    let cleaned = response.text?.trim() || text;
    // Strip conversational prefixes
    cleaned = cleaned.replace(/^(Optimized script:|Script:|Neural output:|Here is the script:|Here is your script:)\s*/i, '');
    // Strip markdown code blocks if the model hallucinates them
    cleaned = cleaned.replace(/```[a-z]*\n?|```/gi, '');

    return sanitizeForTTS(cleaned);
  } catch (e) {
    console.warn("Speech enhancement layer failed, using raw input.");
    return sanitizeForTTS(text);
  }
};

/**
 * Generate Neural Speech
 * Specifically handles the 400 error by throwing a catchable refusal error.
 */
export const generateTTS = async (text: string, voiceName: string) => {
  const sanitizedText = sanitizeForTTS(text);

  if (!sanitizedText || sanitizedText.length < 2) {
    return null;
  }

  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: sanitizedText }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const audioPart = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);

    if (!audioPart) {
      // Catch the "Non-audio response" error case
      const refusalText = response.text;
      console.warn("TTS Model Refusal. Content:", refusalText);
      throw new Error("TTS_REFUSAL");
