  const [clonedVoices, setClonedVoices] = useState<VoiceProfile[]>(ELEVEN_LABS_VOICES);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const encodeWAV = (samples: Float32Array, sampleRate: number) => {
    const buffer = new ArrayBuffer(44 + samples.length * 2);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) v.setUint8(offset + i, string.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 32 + samples.length * 2, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, samples.length * 2, true);
    let offset = 44;
    for (let i = 0; i < samples.length; i++, offset += 2) {
      const s = Math.max(-1, Math.min(1, samples[i]));
      view.setInt16(offset, s < 0 ? s * 0x8000 : s * 0x7FFF, true);
    }
    return buffer;
  };

  const processAudioData = (base64Audio: string) => {
    const binaryString = atob(base64Audio);
    const bytes = new Uint8Array(binaryString.length);
    const int16Data = new Int16Array(bytes.buffer);
    for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
    const floatData = new Float32Array(int16Data.length);
    for (let i = 0; i < int16Data.length; i++) floatData[i] = int16Data[i] / 32768.0;
    const wavBuffer = encodeWAV(floatData, 24000);
    return URL.createObjectURL(new Blob([wavBuffer], { type: 'audio/wav' }));
  };

  const handleGenerate = async () => {
    if (!text || text.trim().length < 2) {
      setErrorMsg("Please enter a script to synthesize.");
      return;
    }
    setLoading(true);
    setErrorMsg(null);
    setAudioUrl(null);
    setVisualUrl(null);

    try {
      let processingText = text;

      // Step 1: Optional Enhancement
      if (shouldEnhance) {
        processingText = await enhanceTextForSpeech(text);
      }

      // Step 2: Synthesis Attempt
      let base64Audio: string | null = null;
      try {
        base64Audio = await generateTTS(processingText, selectedVoice.geminiVoice);
      } catch (synthErr: any) {
        if (synthErr.message === 'TTS_REFUSAL') {
          console.warn("Enhanced text refused by TTS engine. Retrying with raw text...");
          // SILENT FALLBACK: Retry with the original raw text to ensure the user gets audio
          base64Audio = await generateTTS(text, selectedVoice.geminiVoice);
        } else {
          throw synthErr;
        }
      }

      // Step 3: Visual Generation
      let visualPromise = Promise.resolve(null as string | null);
      if (shouldGenerateVisual) {
        visualPromise = summarizeForVisuals(text).then(prompt => generateImage(prompt, '1K', false));
      }

      const imageResult = await visualPromise;

      if (base64Audio) {
        setAudioUrl(processAudioData(base64Audio));
      } else {
        setErrorMsg("The neural engine refused to synthesize this specific content. Try rephrasing.");
      }

      if (imageResult) {
        setVisualUrl(imageResult);
      }

    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || "An unexpected error occurred during synthesis.");
    } finally {
      setLoading(false);
    }
  };

  const handleCloneVoice = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setCloning(true);
    setErrorMsg(null);
    setCloningStatus('Analyzing Voice Identity...');
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = reader.result as string;
        const matchedVoiceId = await classifyVoice(base64, file.type);

        const maleIDs = ['Puck', 'Charon', 'Zephyr', 'Fenrir'];
        const isMale = maleIDs.includes(matchedVoiceId);

        const newVoice: VoiceProfile = {
          id: Math.random().toString(36).substr(2, 9),
          name: `Neural ${file.name.split('.')[0]}`,
          geminiVoice: matchedVoiceId,
          description: `Custom Vocal Clone (${isMale ? 'Male' : 'Female'})`,
          gender: isMale ? 'male' : 'female'
        };
        setClonedVoices([newVoice, ...clonedVoices]);
        setSelectedVoice(newVoice);
        setCloning(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      };
      reader.readAsDataURL(file);
    } catch (error) {
      console.error("Vocal Cloning Error:", error);
      setErrorMsg("Vocal cloning analysis failed. Ensure the audio is clear and under 10MB.");
      setCloning(false);
    }
  };

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20">
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Main Interface */}
        <div className="lg:col-span-8 space-y-6">
          <div className="space-y-4">
            <div className="flex items-center justify-between px-1">
              <label className="text-sm font-bold text-gray-400 uppercase tracking-widest">Neural Synthesis Lab</label>
              <div className="flex gap-4">
                 <button 
                  onClick={() => setShouldEnhance(!shouldEnhance)}
                  className={`flex items-center gap-2 text-[10px] font-bold px-3 py-1.5 rounded-full border transition-all ${shouldEnhance ? 'bg-indigo-500/20 border-indigo-500 text-indigo-400 shadow-[0_0_15px_rgba(99,102,241,0.2)]' : 'bg-white/5 border-white/10 text-gray-500'}`}
                 >
                   <div className={`w-1.5 h-1.5 rounded-full ${shouldEnhance ? 'bg-indigo-500 animate-pulse' : 'bg-gray-600'}`}></div>
                   ENHANCE V3 (ALPHA)
                 </button>
                 <button 
                  onClick={() => setShouldGenerateVisual(!shouldGenerateVisual)}
                  className={`flex items-center gap-2 text-[10px] font-bold px-3 py-1.5 rounded-full border transition-all ${shouldGenerateVisual ? 'bg-emerald-500/20 border-emerald-500 text-emerald-400 shadow-[0_0_15px_rgba(16,185,129,0.2)]' : 'bg-white/5 border-white/10 text-gray-500'}`}
                 >
                   <div className={`w-1.5 h-1.5 rounded-full ${shouldGenerateVisual ? 'bg-emerald-500 animate-pulse' : 'bg-gray-600'}`}></div>
                   SYNC VISUAL FORGE
                 </button>
              </div>
            </div>
            <textarea
              value={text}
              onChange={(e) => { setText(e.target.value); if (errorMsg) setErrorMsg(null); }}
              placeholder="Paste your content here for high-fidelity synthesis..."
              className="w-full h-80 p-8 glass-panel rounded-3xl border-white/10 focus:border-indigo-500/50 outline-none resize-none transition-all text-lg leading-relaxed shadow-2xl font-light"
            />
          </div>

          {errorMsg && (
            <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-2xl flex items-center gap-3 text-red-400 text-sm animate-in fade-in slide-in-from-top-2">
              <svg className="w-5 h-5 shrink-0" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" /></svg>
              {errorMsg}
            </div>
          )}

          <button
            onClick={handleGenerate}
            disabled={loading || !text}
            className={`w-full py-6 accent-gradient rounded-2xl font-bold flex items-center justify-center gap-3 transition-all text-xl shadow-xl shadow-indigo-500/20 ${loading ? 'opacity-50 cursor-wait' : 'hover:shadow-2xl hover:scale-[1.01] active:scale-[0.99]'}`}
          >
            {loading ? (
              <><div className="w-6 h-6 border-3 border-white/30 border-t-white rounded-full animate-spin" /> Neural Engine Active...</>
            ) : (
              <><svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg> Master Synthesis</>
            )}
          </button>

          {(audioUrl || visualUrl) && (
            <div className="grid grid-cols-1 md:grid-cols-12 gap-8 animate-in slide-in-from-top-8">
              {visualUrl && (
                <div className="md:col-span-5 aspect-square glass-panel rounded-3xl border-emerald-500/20 overflow-hidden shadow-2xl group relative">
                  <img src={visualUrl} className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110" alt="Script Visual Backdrop" />
                  <div className="absolute top-4 left-4 bg-emerald-500/40 backdrop-blur-md px-3 py-1 rounded-full border border-emerald-500/50 text-[10px] font-bold text-white shadow-lg">SYNCED VISUAL</div>
                </div>
