              <div className={`${visualUrl ? 'md:col-span-7' : 'md:col-span-12'} p-8 glass-panel rounded-3xl border-indigo-500/30 flex flex-col justify-between shadow-2xl bg-indigo-500/5`}>
                <div className="space-y-6">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-4">
                      <div className={`w-16 h-16 rounded-2xl flex items-center justify-center font-bold text-2xl shadow-inner ${selectedVoice.gender === 'female' ? 'bg-pink-500/20 text-pink-400' : 'bg-blue-500/20 text-blue-400'}`}>
                        {selectedVoice.name.charAt(0)}
                      </div>
                      <div>
                        <h4 className="font-bold text-white text-xl font-outfit">{selectedVoice.name}</h4>
                        <p className="text-xs text-gray-400 uppercase tracking-widest">{selectedVoice.description} • V3 OPTIMIZED</p>
                      </div>
                    </div>
                    {audioUrl && (
                      <a href={audioUrl} download={`${selectedVoice.name}-neural-v3.wav`} className="p-4 bg-indigo-500 rounded-2xl hover:bg-indigo-600 transition-all text-white shadow-2xl shadow-indigo-500/40">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                      </a>
                    )}
                  </div>

                  <div className="bg-black/40 p-6 rounded-3xl border border-white/5 shadow-inner">
                    <div className="flex items-center gap-2 mb-4">
                       <span className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse"></span>
                       <span className="text-[10px] text-indigo-400 font-bold uppercase tracking-[0.2em]">Neural Audio Stream</span>
                    </div>
                    {audioUrl && <audio ref={audioRef} src={audioUrl} controls className="w-full accent-indigo-500" />}
                  </div>
                </div>

                <div className="mt-8 pt-6 border-t border-white/5 text-gray-500 text-[10px] font-bold uppercase tracking-widest flex items-center justify-between">
                   <div className="flex items-center gap-2">
                     <svg className="w-4 h-4 text-emerald-500" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M2.166 4.999A11.954 11.954 0 0010 1.944 11.954 11.954 0 0017.834 5c.11.65.166 1.32.166 2.001 0 5.225-3.34 9.67-8 11.317C5.34 16.67 2 12.225 2 7c0-.682.057-1.35.166-2.001zm11.541 3.708a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                     Neural Stream Active
                   </div>
                   <span className="text-gray-600">Visuals: {shouldGenerateVisual ? 'ENABLED' : 'DISABLED'}</span>
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Neural Library Sidebar */}
        <div className="lg:col-span-4 space-y-6">
          <div className="glass-panel rounded-3xl p-6 border-white/5 space-y-6 shadow-xl sticky top-24">
            <div className="flex items-center justify-between">
              <label className="text-sm font-bold text-gray-400 uppercase tracking-widest">Neural Identities</label>
              <button 
                onClick={() => fileInputRef.current?.click()} 
                disabled={cloning}
                className={`text-[10px] px-4 py-2 rounded-full font-bold transition-all shadow-lg ${cloning ? 'bg-gray-700 text-gray-500 cursor-not-allowed' : 'bg-indigo-500 text-white hover:bg-indigo-600 hover:scale-105'}`}
              >
                {cloning ? 'ANALYZING...' : 'CLONE NEW VOICE'}
              </button>
              <input type="file" ref={fileInputRef} onChange={handleCloneVoice} accept="audio/*" className="hidden" />
            </div>

            <div className="space-y-3 max-h-[640px] overflow-y-auto pr-2 custom-scrollbar">
              {cloning && (
                <div className="p-4 rounded-2xl bg-indigo-500/5 border border-indigo-500/20 flex items-center gap-4 animate-pulse">
                  <div className="w-10 h-10 rounded-xl bg-indigo-500/20 flex items-center justify-center">
                    <div className="w-4 h-4 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                  </div>
                  <div className="space-y-1">
                    <p className="text-xs font-bold text-indigo-400">{cloningStatus}</p>
                    <p className="text-[9px] text-gray-500 uppercase tracking-widest">Processing vocal fingerprint...</p>
                  </div>
                </div>
              )}

              {clonedVoices.map((voice) => (
                <button
                  key={voice.id}
                  onClick={() => { setSelectedVoice(voice); setAudioUrl(null); setErrorMsg(null); }}
                  className={`w-full p-4 rounded-2xl text-left border transition-all flex items-center gap-4 group ${
                    selectedVoice.id === voice.id ? 'bg-indigo-500/20 border-indigo-500 shadow-xl' : 'bg-white/5 border-white/10 text-gray-400 hover:bg-white/10'
                  }`}
                >
                  <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-bold shrink-0 transition-all ${
                    selectedVoice.id === voice.id 
                    ? 'bg-indigo-500 text-white scale-110 shadow-lg' 
                    : voice.gender === 'female' ? 'bg-pink-500/10 text-pink-400/50' : 'bg-blue-500/10 text-blue-400/50'
                  }`}>
                    {voice.name.charAt(0)}
                  </div>
                  <div className="flex-1 overflow-hidden">
                    <div className="flex items-center gap-2">
                       <p className={`font-bold truncate text-sm transition-colors ${selectedVoice.id === voice.id ? 'text-white' : 'text-gray-300'}`}>{voice.name}</p>
                       <span className={`text-[8px] px-1.5 py-0.5 rounded-md font-bold uppercase border ${voice.gender === 'female' ? 'bg-pink-500/10 text-pink-500/70 border-pink-500/20' : 'bg-blue-500/10 text-blue-500/70 border-blue-500/20'}`}>
                         {voice.gender === 'female' ? 'Fem' : 'Male'}
                       </span>
                    </div>
                    <p className="text-[10px] opacity-60 truncate tracking-tight">{voice.description}</p>
                  </div>
                  <div className={`w-2 h-2 rounded-full transition-all ${selectedVoice.id === voice.id ? 'bg-indigo-500 shadow-[0_0_8px_rgba(99,102,241,1)]' : 'bg-transparent'}`}></div>
                </button>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TTSView;

import { GoogleGenAI, Modality, Type, GenerateContentResponse } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export class QuotaError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "QuotaError";
  }
}

export class PermissionError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "PermissionError";
  }
}

const handleApiError = (error: any) => {
  console.error("API Error Details:", error);
  const errorMessage = error?.message || String(error);

  if (errorMessage.includes("429") || errorMessage.toLowerCase().includes("quota exceeded") || errorMessage.toLowerCase().includes("too many requests")) {
    throw new QuotaError("The current API key has exceeded its quota limit.");
  }

  if (errorMessage.includes("403") || errorMessage.toLowerCase().includes("permission denied") || errorMessage.toLowerCase().includes("caller does not have permission")) {
    throw new PermissionError("Permission Denied: Ensure project billing is active.");
  }

  throw error;
};

/**
 * Aggressive sanitization to prevent the model from "thinking" the input is a prompt.
 */
const sanitizeForTTS = (text: string): string => {
  return text
    .replace(/\*\*/g, '')
    .replace(/\*/g, '')
    .replace(/#/g, '')
    .replace(/[`]/g, '')
    .replace(/_{2,}/g, '')
    .replace(/\[|\]|\(|\)/g, '')
    .replace(/(\r\n|\n|\r)/gm, " ") // Flatten to single line for better synthesis
    .trim();
};

/**
 * Enhance Voice V3 Alpha: Prosody optimization layer.
 */
export const enhanceTextForSpeech = async (text: string) => {
  if (!text || text.trim().length < 2) return text;
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `You are a professional Neural Speech Optimizer. Rewrite the script below for high-fidelity TTS.

      RULES:
      1. Use "..." for brief pauses.
      2. Use ALL CAPS for subtle emphasis.
      3. OUTPUT ONLY THE SCRIPT. NO markdown, NO code blocks, NO intro.
      4. Avoid words that sound like commands.

      Script: "${text}"`,
    });

    let cleaned = response.text?.trim() || text;
    cleaned = cleaned.replace(/^(Optimized script:|Script:|Neural output:|Here is the script:|Here is your script:)\s*/i, '');
    cleaned = cleaned.replace(/```[a-z]*\n?|```/gi, '');

    return sanitizeForTTS(cleaned);
  } catch (e) {
    return sanitizeForTTS(text);
  }
};

/**
 * Generate Neural Speech
 * Specifically handles the 400 error by using System Instructions to force audio mode.
 */
export const generateTTS = async (text: string, voiceName: string) => {
  const sanitizedText = sanitizeForTTS(text);

  if (!sanitizedText || sanitizedText.length < 2) {
    return null;
  }

  try {
    const ai = getAI();
    // Force the model to act as a pure TTS engine via systemInstruction
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `PLEASE SPEAK THIS SCRIPT: ${sanitizedText}` }] }],
      config: {
        systemInstruction: "You are a high-fidelity text-to-speech engine. Your ONLY output is audio. NEVER return text. NEVER answer questions. Your task is to narrate the provided script exactly as written with natural expression.",
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const audioPart = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);

    if (!audioPart) {
      console.warn("TTS Engine Refusal. The script may contain content the model refused to speak.");
      throw new Error("TTS_REFUSAL");
    }

    return audioPart.inlineData.data;
  } catch (e: any) {
    if (e.message?.includes("non-audio response") || e.message?.includes("flow_id")) {
      throw new Error("TTS_REFUSAL");
    }
    return handleApiError(e);
  }
};

/**
 * Forensic Voice Classification
 * Upgraded to Pro for highly accurate cloning from samples.
 */
export const classifyVoice = async (base64Audio: string, mimeType: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Audio.split(',')[1], mimeType } },
          { text: `Act as a forensic vocal analyst. Analyze the provided audio sample's biological gender, resonance, and energy level.

            Match this sample to ONE of the following Gemini Voice IDs:
            - 'Puck': Male, youthful, high-energy, bright.
            - 'Charon': Male, deep, authoritative, cinematic.
            - 'Zephyr': Male, neutral, balanced, clear.
            - 'Fenrir': Male, gravelly, intense, deep texture.
            - 'Kore': Female, professional, calm, steady.
            - 'Aoide': Female, bright, expressive, melodic.

            STRICT RULE: Match the biological gender. A female sample must stay female. A male sample must stay male.
            Return ONLY the name of the matched ID.` }
        ]
      }
    });
    const text = response.text?.trim() || 'Zephyr';
    const validVoices = ['Puck', 'Charon', 'Zephyr', 'Kore', 'Aoide', 'Fenrir'];
    return validVoices.find(v => text.includes(v)) || 'Zephyr';
  } catch (e) { return handleApiError(e); }
};

export const generateVideo = async (prompt: string, aspectRatio: '16:9' | '9:16', startImage?: string) => {
  try {
    const ai = getAI();
    const payload: any = {
      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt || 'A cinematic scene',
      config: { numberOfVideos: 1, resolution: '720p', aspectRatio }
    };
    if (startImage) payload.image = { imageBytes: startImage.split(',')[1], mimeType: 'image/png' };
    let operation = await ai.models.generateVideos(payload);
    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }
    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
  } catch (e) { return handleApiError(e); }
};

export const generateImage = async (prompt: string, size: '1K' | '2K' | '4K', useNanoPro: boolean = false) => {
  try {
    const ai = getAI();
    const model = (useNanoPro || size !== '1K') ? 'gemini-3-pro-image-preview' : 'gemini-2.5-flash-image';
    const imageConfig: any = { aspectRatio: "1:1" };
    if (model === 'gemini-3-pro-image-preview') imageConfig.imageSize = size;
    const response = await ai.models.generateContent({
      model,
      contents: { parts: [{ text: prompt }] },
      config: { imageConfig },
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    return null;
  } catch (e) { return handleApiError(e); }
};

export const analyzeMedia = async (fileBase64: string, mimeType: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { data: fileBase64.split(',')[1], mimeType } },
          { text: "Provide transcript and summary JSON." }
        ]
      },
      config: {
          responseMimeType: "application/json",
          responseSchema: {
              type: Type.OBJECT,
              properties: {
                  transcript: { type: Type.STRING },
                  summary: { type: Type.STRING },
                  sequencedScript: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        type: { type: Type.STRING },
                        text: { type: Type.STRING }
                      },
                      required: ["type", "text"]
                    }
                  }
              },
              required: ["transcript", "summary", "sequencedScript"]
          }
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (e) { return handleApiError(e); }
};

export const analyzeUrl = async (url: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze URL: ${url}.`,
      config: { tools: [{ googleSearch: {} }] }
    });
    const text = response.text || '';
    return { 
      transcript: text, 
      summary: "Analysis complete.", 
      sequencedScript: [{ type: "Analysis", text: text }],
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (e) { return handleApiError(e); }
};

export const summarizeForVisuals = async (text: string) => {
  try {
    const ai = getAI();
