const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export class QuotaError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "QuotaError";
  }
}

export class PermissionError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "PermissionError";
  }
}

const handleApiError = (error: any) => {
  console.error("API Error Details:", error);
  const errorMessage = error?.message || String(error);

  if (errorMessage.includes("429") || errorMessage.toLowerCase().includes("quota exceeded") || errorMessage.toLowerCase().includes("too many requests")) {
    throw new QuotaError("The current API key has exceeded its quota limit.");
  }

  if (errorMessage.includes("403") || errorMessage.toLowerCase().includes("permission denied") || errorMessage.toLowerCase().includes("caller does not have permission")) {
    throw new PermissionError("Permission Denied: Ensure project billing is active.");
  }

  throw error;
};

const sanitizeForTTS = (text: string): string => {
  return text
    .replace(/\*\*/g, '')
    .replace(/\*/g, '')
    .replace(/#/g, '')
    .replace(/[`]/g, '')
    .replace(/_{2,}/g, '')
    .replace(/\[|\]|\(|\)/g, '')
    .replace(/(\r\n|\n|\r)/gm, " ")
    .trim();
};

export const enhanceTextForSpeech = async (text: string) => {
  if (!text || text.trim().length < 2) return text;
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `You are a professional Neural Speech Optimizer. Rewrite the script below for high-fidelity TTS.

      RULES:
      1. Use "..." for brief pauses.
      2. Use ALL CAPS for subtle emphasis.
      3. OUTPUT ONLY THE SCRIPT. NO markdown, NO code blocks, NO intro.

      Script: "${text}"`,
    });

    let cleaned = response.text?.trim() || text;
    cleaned = cleaned.replace(/^(Optimized script:|Script:|Neural output:|Here is the script:|Here is your script:)\s*/i, '');
    cleaned = cleaned.replace(/```[a-z]*\n?|```/gi, '');

    return sanitizeForTTS(cleaned);
  } catch (e) {
    return sanitizeForTTS(text);
  }
};

export const generateTTS = async (text: string, voiceName: string, settings?: VoiceSettings) => {
  const sanitizedText = sanitizeForTTS(text);

  if (!sanitizedText || sanitizedText.length < 2) {
    return null;
  }

  // Construct dynamic instruction based on user settings
  const pitchDesc = settings?.pitch && settings.pitch > 1.2 ? "high pitch" : (settings?.pitch && settings.pitch < 0.8 ? "low pitch" : "natural pitch");
  const rateDesc = settings?.rate && settings.rate > 1.3 ? "fast" : (settings?.rate && settings.rate < 0.7 ? "slowly" : "natural speed");
  const styleDesc = settings?.style || 'expressive';

  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `[STYLE: ${styleDesc}, PITCH: ${pitchDesc}, RATE: ${rateDesc}] SPEAK: ${sanitizedText}` }] }],
      config: {
        systemInstruction: `You are an advanced TTS engine. 
        - DO NOT output text. 
        - Speak in a ${styleDesc} manner.
        - Use a ${pitchDesc} and speak ${rateDesc}.
        - Narrate the provided script exactly as written.`,
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const audioPart = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
    if (!audioPart) throw new Error("TTS_REFUSAL");
    return audioPart.inlineData.data;
  } catch (e: any) {
    if (e.message?.includes("non-audio response") || e.message?.includes("flow_id")) {
      throw new Error("TTS_REFUSAL");
    }
    return handleApiError(e);
  }
};

export const classifyVoice = async (base64Audio: string, mimeType: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Audio.split(',')[1], mimeType } },
          { text: `Analyze this audio sample's vocal identity forensicly.

            EXTRACT:
            1. GENDER (Male/Female)
            2. TIMBRE (Deep, Bright, Silky, Gravelly)
            3. PITCH CENTER (Low, Balanced, High)
            4. ACCENT/STYLE (Professional, Casual, Dramatic)

            MATCH TO NEURAL ID:
            - 'Puck': Youthful male, high energy.
            - 'Charon': Deep male, authoritative.
            - 'Zephyr': Balanced male, neutral.
            - 'Fenrir': Gravelly male, intense.
            - 'Kore': Calm female, professional.
            - 'Aoide': Bright female, melodic.

            Return JSON: { "id": "VoiceName", "traits": ["trait1", "trait2"], "summary": "One line desc" }` }
        ]
      },
      config: {
        responseMimeType: "application/json"
      }
    });
    const result = JSON.parse(response.text || '{}');
    const validVoices = ['Puck', 'Charon', 'Zephyr', 'Kore', 'Aoide', 'Fenrir'];
    const matchedId = validVoices.find(v => v === result.id) || 'Zephyr';
    return { id: matchedId, traits: result.traits || [], summary: result.summary || "Balanced Profile" };
  } catch (e) { 
    return { id: 'Zephyr', traits: ["Standard"], summary: "Standard Balanced Profile" };
  }
};

export const generateVideo = async (prompt: string, aspectRatio: '16:9' | '9:16', startImage?: string) => {
  try {
    const ai = getAI();
    const payload: any = {
      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt || 'A cinematic scene',
      config: { numberOfVideos: 1, resolution: '720p', aspectRatio }
    };
    if (startImage) payload.image = { imageBytes: startImage.split(',')[1], mimeType: 'image/png' };
    let operation = await ai.models.generateVideos(payload);
    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }
    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
  } catch (e) { return handleApiError(e); }
};

export const generateImage = async (prompt: string, size: '1K' | '2K' | '4K', useNanoPro: boolean = false) => {
  try {
    const ai = getAI();
    const model = (useNanoPro || size !== '1K') ? 'gemini-3-pro-image-preview' : 'gemini-2.5-flash-image';
    const imageConfig: any = { aspectRatio: "1:1" };
    if (model === 'gemini-3-pro-image-preview') imageConfig.imageSize = size;
    const response = await ai.models.generateContent({
      model,
      contents: { parts: [{ text: prompt }] },
      config: { imageConfig },
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    return null;
  } catch (e) { return handleApiError(e); }
};

export const analyzeMedia = async (fileBase64: string, mimeType: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { data: fileBase64.split(',')[1], mimeType } },
          { text: "Provide transcript and summary JSON." }
        ]
      },
      config: {
          responseMimeType: "application/json",
          responseSchema: {
              type: Type.OBJECT,
              properties: {
                  transcript: { type: Type.STRING },
                  summary: { type: Type.STRING },
                  sequencedScript: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        type: { type: Type.STRING },
                        text: { type: Type.STRING }
                      },
                      required: ["type", "text"]
                    }
                  }
              },
              required: ["transcript", "summary", "sequencedScript"]
          }
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (e) { return handleApiError(e); }
};

export const analyzeUrl = async (url: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze URL: ${url}.`,
      config: { tools: [{ googleSearch: {} }] }
    });
    const text = response.text || '';
    return { 
      transcript: text, 
      summary: "Analysis complete.", 
      sequencedScript: [{ type: "Analysis", text: text }],
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (e) { return handleApiError(e); }
};

export const summarizeForVisuals = async (text: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate a short, cinematic 1:1 image prompt (max 30 words) that represents the mood of this text: "${text}"`,
    });
    return response.text || "Professional cinematic studio backdrop";
  } catch (e) { return "Professional cinematic studio backdrop"; }
};

import React, { useState, useRef } from 'react';
import { ELEVEN_LABS_VOICES, VoiceProfile, VoiceSettings, DEFAULT_SETTINGS } from '../types';
import { generateTTS, classifyVoice, enhanceTextForSpeech, summarizeForVisuals, generateImage } from '../services/geminiService';

const TTSView: React.FC = () => {
  const [text, setText] = useState('');
  const [selectedVoice, setSelectedVoice] = useState<VoiceProfile>(ELEVEN_LABS_VOICES.find(v => v.name === 'Brain') || ELEVEN_LABS_VOICES[0]);
  const [loading, setLoading] = useState(false);
  const [cloning, setCloning] = useState(false);
  const [cloningStatus, setCloningStatus] = useState('');
  const [pendingClone, setPendingClone] = useState<VoiceProfile | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [visualUrl, setVisualUrl] = useState<string | null>(null);
  const [shouldEnhance, setShouldEnhance] = useState(true);
  const [shouldGenerateVisual, setShouldGenerateVisual] = useState(true);
  const [clonedVoices, setClonedVoices] = useState<VoiceProfile[]>(ELEVEN_LABS_VOICES);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const encodeWAV = (samples: Float32Array, sampleRate: number) => {
    const buffer = new ArrayBuffer(44 + samples.length * 2);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) v.setUint8(offset + i, string.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 32 + samples.length * 2, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, samples.length * 2, true);
    let offset = 44;
    for (let i = 0; i < samples.length; i++, offset += 2) {
      const s = Math.max(-1, Math.min(1, samples[i]));
      view.setInt16(offset, s < 0 ? s * 0x8000 : s * 0x7FFF, true);
    }
    return buffer;
  };

  const processAudioData = (base64Audio: string) => {
    try {
      const binaryString = atob(base64Audio);
      const len = binaryString.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
      const int16Data = new Int16Array(bytes.buffer, 0, Math.floor(len / 2));
      const floatData = new Float32Array(int16Data.length);
      for (let i = 0; i < int16Data.length; i++) floatData[i] = int16Data[i] / 32768.0;
      const wavBuffer = encodeWAV(floatData, 24000);
      return URL.createObjectURL(new Blob([wavBuffer], { type: 'audio/wav' }));
    } catch (e) {
      return null;
    }
  };

  const updateSelectedVoiceSetting = <K extends keyof VoiceSettings>(key: K, value: VoiceSettings[K]) => {
    const updated = { ...selectedVoice, settings: { ...selectedVoice.settings, [key]: value } };
    setSelectedVoice(updated);
    setClonedVoices(prev => prev.map(v => v.id === updated.id ? updated : v));
  };

  const handleGenerate = async () => {
    if (!text || text.trim().length < 2) {
      setErrorMsg("Please enter a script to synthesize.");
      return;
    }
    setLoading(true);
    setErrorMsg(null);
    setAudioUrl(null);
    setVisualUrl(null);

    try {
      let processingText = text;
      if (shouldEnhance) processingText = await enhanceTextForSpeech(text);

      let base64Audio: string | null = null;
      try {
        base64Audio = await generateTTS(processingText, selectedVoice.geminiVoice, selectedVoice.settings);
      } catch (synthErr: any) {
        if (synthErr.message === 'TTS_REFUSAL') {
          base64Audio = await generateTTS(text.slice(0, 500), selectedVoice.geminiVoice, selectedVoice.settings);
        } else {
          throw synthErr;
        }
      }

      let visualPromise = Promise.resolve(null as string | null);
      if (shouldGenerateVisual) {
        visualPromise = summarizeForVisuals(text).then(prompt => generateImage(prompt, '1K', false));
      }
      const imageResult = await visualPromise;

      if (base64Audio) {
        const url = processAudioData(base64Audio);
        if (url) setAudioUrl(url);
        else setErrorMsg("Neural audio stream failed.");
      } else {
        setErrorMsg("Synthesis engine returned an invalid response.");
      }

      if (imageResult) setVisualUrl(imageResult);
    } catch (err: any) {
      setErrorMsg(err.message || "An unexpected error occurred.");
    } finally {
      setLoading(false);
    }
  };

  const handleCloneVoice = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setCloning(true);
    setErrorMsg(null);
    setCloningStatus('Mapping Vocal DNA...');
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = reader.result as string;
        const analysis = await classifyVoice(base64, file.type);
        const isMale = ['Puck', 'Charon', 'Zephyr', 'Fenrir'].includes(analysis.id);

        const newVoice: VoiceProfile = {
          id: Math.random().toString(36).substr(2, 9),
          name: `Clone: ${file.name.split('.')[0]}`,
          geminiVoice: analysis.id,
          description: analysis.summary,
          gender: isMale ? 'male' : 'female',
          traits: analysis.traits,
          settings: { ...DEFAULT_SETTINGS }
        };
        setPendingClone(newVoice);
        setCloning(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      };
      reader.readAsDataURL(file);
    } catch (error) {
      setErrorMsg("Vocal analysis failed.");
      setCloning(false);
    }
  };

  const handlePreviewNeuralTest = async () => {
    if (!pendingClone) return;
    setCloningStatus('Synthesizing Neural Test...');
    setCloning(true);
    try {
      const base64 = await generateTTS("Hello, this is my new neural identity. Does it sound accurate?", pendingClone.geminiVoice, pendingClone.settings);
      if (base64) {
        const url = processAudioData(base64);
        if (url) {
          const audio = new Audio(url);
          audio.play();
        }
      }
    } catch (e) {
      setErrorMsg("Preview test failed.");
    } finally {
      setCloning(false);
    }
  };

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20">

      {/* Clone Wizard Modal */}
      {pendingClone && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-gray-950/90 backdrop-blur-xl p-4">
          <div className="max-w-xl w-full glass-panel rounded-[2.5rem] p-10 space-y-8 border-indigo-500/20 shadow-2xl animate-in zoom-in-95">
            <div className="text-center space-y-2">
              <div className="w-20 h-20 rounded-3xl accent-gradient mx-auto flex items-center justify-center text-3xl shadow-lg">🧬</div>
              <h2 className="text-3xl font-bold font-outfit text-white">Neural Verification</h2>
              <p className="text-gray-400">Review the detected vocal traits before finalization.</p>
            </div>

            <div className="space-y-6">
               <div className="bg-white/5 p-6 rounded-3xl border border-white/5">
                  <div className="flex justify-between items-center mb-4">
                    <span className="text-xs font-bold text-indigo-400 uppercase tracking-widest">Detected Identity</span>
                    <span className="text-[10px] px-2 py-1 bg-indigo-500/20 rounded-md font-bold text-indigo-300">{pendingClone.geminiVoice} Engine</span>
                  </div>
                  <p className="text-lg font-bold text-white mb-2">{pendingClone.name}</p>
                  <p className="text-sm text-gray-400 italic mb-4">"{pendingClone.description}"</p>
                  <div className="flex flex-wrap gap-2">
                    {pendingClone.traits?.map(trait => (
                      <span key={trait} className="px-3 py-1 bg-white/5 border border-white/10 rounded-full text-[10px] text-gray-300 font-bold uppercase tracking-wider">{trait}</span>
                    ))}
                  </div>
               </div>

               <div className="grid grid-cols-2 gap-4">
                 <button 
                  onClick={handlePreviewNeuralTest}
                  disabled={cloning}
                  className="py-4 bg-white/5 border border-white/10 rounded-2xl font-bold text-sm hover:bg-white/10 transition-all flex items-center justify-center gap-2"
                 >
                   {cloning ? <div className="w-4 h-4 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin"></div> : 'Neural Test Sample'}
                 </button>
                 <button 
                  onClick={() => { setClonedVoices([pendingClone, ...clonedVoices]); setSelectedVoice(pendingClone); setPendingClone(null); }}
                  className="py-4 accent-gradient rounded-2xl font-bold text-sm hover:shadow-[0_0_20px_rgba(99,102,241,0.4)] transition-all"
                 >
                   Finalize Clone
                 </button>
               </div>
               <button onClick={() => setPendingClone(null)} className="w-full text-xs text-gray-500 font-bold uppercase tracking-widest hover:text-white transition-colors">Cancel Identity Mapping</button>
            </div>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

        <div className="lg:col-span-8 space-y-6">
          <div className="space-y-4">
            <div className="flex items-center justify-between px-1">
              <label className="text-sm font-bold text-gray-400 uppercase tracking-widest">Script Editor</label>
              <div className="flex gap-4">
                 <button 
                  onClick={() => setShouldEnhance(!shouldEnhance)}
                  className={`flex items-center gap-2 text-[10px] font-bold px-3 py-1.5 rounded-full border transition-all ${shouldEnhance ? 'bg-indigo-500/20 border-indigo-500 text-indigo-400' : 'bg-white/5 border-white/10 text-gray-500'}`}
                 >
                   ENHANCE V3
                 </button>
                 <button 
                  onClick={() => setIsSettingsOpen(!isSettingsOpen)}
                  className={`flex items-center gap-2 text-[10px] font-bold px-3 py-1.5 rounded-full border transition-all ${isSettingsOpen ? 'bg-purple-500/20 border-purple-500 text-purple-400' : 'bg-white/5 border-white/10 text-gray-500'}`}
                 >
                   VOICE MASTER SETTINGS
                 </button>
              </div>
            </div>

            {isSettingsOpen && (
              <div className="p-8 glass-panel rounded-3xl border-purple-500/20 animate-in slide-in-from-top-4 space-y-8">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                  <div className="space-y-4">
                    <div className="flex justify-between text-xs font-bold uppercase text-gray-400 tracking-widest">
                      <span>Neural Pitch</span>
                      <span className="text-purple-400">{selectedVoice.settings.pitch}x</span>
                    </div>
                    <input 
                      type="range" min="0.5" max="1.5" step="0.1" 
                      value={selectedVoice.settings.pitch}
                      onChange={(e) => updateSelectedVoiceSetting('pitch', parseFloat(e.target.value))}
                      className="w-full accent-purple-500"
                    />
                  </div>
                  <div className="space-y-4">
                    <div className="flex justify-between text-xs font-bold uppercase text-gray-400 tracking-widest">
                      <span>Speaking Rate</span>
                      <span className="text-purple-400">{selectedVoice.settings.rate}x</span>
                    </div>
                    <input 
                      type="range" min="0.5" max="2.0" step="0.1" 
                      value={selectedVoice.settings.rate}
                      onChange={(e) => updateSelectedVoiceSetting('rate', parseFloat(e.target.value))}
                      className="w-full accent-purple-500"
                    />
                  </div>
                  <div className="space-y-4">
                    <div className="flex justify-between text-xs font-bold uppercase text-gray-400 tracking-widest">
                      <span>Neural Gain</span>
                      <span className="text-purple-400">{Math.round(selectedVoice.settings.volume * 100)}%</span>
                    </div>
                    <input 
                      type="range" min="0" max="1" step="0.1" 
                      value={selectedVoice.settings.volume}
                      onChange={(e) => updateSelectedVoiceSetting('volume', parseFloat(e.target.value))}
                      className="w-full accent-purple-500"
                    />
                  </div>
                </div>
                <div className="flex flex-wrap gap-3">
                  {(['neutral', 'expressive', 'calm', 'authoritative', 'whisper'] as const).map(style => (
                    <button
                      key={style}
                      onClick={() => updateSelectedVoiceSetting('style', style)}
                      className={`px-4 py-2 rounded-xl text-[10px] font-bold uppercase tracking-widest border transition-all ${selectedVoice.settings.style === style ? 'bg-purple-500 border-purple-500 text-white' : 'bg-white/5 border-white/10 text-gray-500'}`}
                    >
                      {style}
                    </button>
                  ))}
                </div>
              </div>
            )}

            <textarea
              value={text}
              onChange={(e) => { setText(e.target.value); if (errorMsg) setErrorMsg(null); }}
              placeholder="The script is the foundation of the neural performance..."
              className="w-full h-80 p-8 glass-panel rounded-3xl border-white/10 focus:border-indigo-500/50 outline-none resize-none transition-all text-lg leading-relaxed shadow-2xl font-light"
            />
          </div>

          <button
            onClick={handleGenerate}
            disabled={loading || !text}
            className={`w-full py-6 accent-gradient rounded-2xl font-bold flex items-center justify-center gap-3 transition-all text-xl shadow-xl ${loading ? 'opacity-50' : 'hover:scale-[1.01]'}`}
          >
            {loading ? <div className="w-6 h-6 border-3 border-white/30 border-t-white rounded-full animate-spin" /> : 'Synthesize Master Audio'}
          </button>

          {(audioUrl || visualUrl) && (
            <div className="grid grid-cols-1 md:grid-cols-12 gap-8 animate-in slide-in-from-top-8">
              {visualUrl && (
                <div className="md:col-span-5 aspect-square glass-panel rounded-3xl border-emerald-500/20 overflow-hidden shadow-2xl group relative">
                  <img src={visualUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000" alt="Script Visual" />
                </div>
              )}
              <div className={`${visualUrl ? 'md:col-span-7' : 'md:col-span-12'} p-8 glass-panel rounded-3xl border-indigo-500/30 flex flex-col justify-between shadow-2xl bg-indigo-500/5`}>
                <div className="space-y-6">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-4">
                      <div className="w-16 h-16 rounded-2xl flex items-center justify-center font-bold text-2xl shadow-inner bg-indigo-500/20 text-indigo-400">
                        {selectedVoice.name.charAt(0)}
                      </div>
                      <div>
                        <h4 className="font-bold text-white text-xl font-outfit">{selectedVoice.name}</h4>
                        <p className="text-[10px] text-gray-400 uppercase tracking-widest">Neural Rendered Performance</p>
                      </div>
                    </div>
                  </div>
                  <div className="bg-black/40 p-6 rounded-3xl border border-white/5">
                    {audioUrl && <audio ref={audioRef} src={audioUrl} controls className="w-full accent-indigo-500" />}
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>

        <div className="lg:col-span-4 space-y-6">
          <div className="glass-panel rounded-3xl p-6 border-white/5 space-y-6 shadow-xl sticky top-24">
            <div className="flex items-center justify-between">
              <label className="text-sm font-bold text-gray-400 uppercase tracking-widest">Identity Library</label>
              <button 
                onClick={() => fileInputRef.current?.click()} 
                disabled={cloning}
                className="text-[10px] px-4 py-2 rounded-full font-bold bg-indigo-500 text-white hover:bg-indigo-600 transition-all shadow-lg"
              >
                {cloning ? 'ANALYZING...' : 'CLONE VOICE'}
              </button>
              <input type="file" ref={fileInputRef} onChange={handleCloneVoice} accept="audio/*" className="hidden" />
            </div>

            <div className="space-y-3 max-h-[640px] overflow-y-auto pr-2 custom-scrollbar">
              {clonedVoices.map((voice) => (
                <button
                  key={voice.id}
                  onClick={() => { setSelectedVoice(voice); setAudioUrl(null); }}
                  className={`w-full p-4 rounded-2xl text-left border transition-all flex items-center gap-4 group ${
                    selectedVoice.id === voice.id ? 'bg-indigo-500/20 border-indigo-500 shadow-xl' : 'bg-white/5 border-white/10 text-gray-400 hover:bg-white/10'
                  }`}
                >
                  <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-bold shrink-0 transition-all ${
                    selectedVoice.id === voice.id ? 'bg-indigo-500 text-white' : 'bg-white/10'
                  }`}>
                    {voice.name.charAt(0)}
                  </div>
                  <div className="flex-1 overflow-hidden">
                    <div className="flex items-center gap-2">
                       <p className={`font-bold truncate text-sm transition-colors ${selectedVoice.id === voice.id ? 'text-white' : 'text-gray-300'}`}>{voice.name}</p>
                       <span className="text-[8px] px-1.5 py-0.5 rounded-md font-bold uppercase border bg-white/5 border-white/10">
                         {voice.gender === 'female' ? 'Fem' : 'Male'}
                       </span>
                    </div>
                    <p className="text-[10px] opacity-60 truncate tracking-tight">{voice.description}</p>
                  </div>
                </button>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TTSView;

