  DASHBOARD = 'dashboard',
  TTS = 'tts',
  VIDEO_GEN = 'video_gen',
  IMAGE_GEN = 'image_gen',
  MEDIA_UNDERSTANDING = 'media_understanding',
  LIVE_CHAT = 'live_chat'
}

export interface VoiceSettings {
  pitch: number; // 0.5 to 1.5
  rate: number;  // 0.5 to 2.0
  volume: number; // 0 to 1.0
