import { GoogleGenAI, Modality, Type, GenerateContentResponse } from "@google/genai";
import { VoiceSettings } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export class QuotaError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "QuotaError";
  }
}

export class PermissionError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "PermissionError";
  }
}

const handleApiError = (error: any) => {
  console.error("API Error Details:", error);
  const errorMessage = error?.message || String(error);

  if (errorMessage.includes("429") || errorMessage.toLowerCase().includes("quota exceeded") || errorMessage.toLowerCase().includes("too many requests")) {
    throw new QuotaError("The current API key has exceeded its quota limit.");
  }

  if (errorMessage.includes("403") || errorMessage.toLowerCase().includes("permission denied") || errorMessage.toLowerCase().includes("caller does not have permission")) {
    throw new PermissionError("Permission Denied: Ensure project billing is active.");
  }

  throw error;
};

const sanitizeForTTS = (text: string): string => {
  return text
    .replace(/\*\*/g, '')
    .replace(/\*/g, '')
    .replace(/#/g, '')
    .replace(/[`]/g, '')
    .replace(/_{2,}/g, '')
    .replace(/\[|\]|\(|\)/g, '')
    .replace(/(\r\n|\n|\r)/gm, " ")
    .trim();
};

export const enhanceTextForSpeech = async (text: string) => {
  if (!text || text.trim().length < 2) return text;
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `You are a professional Neural Speech Optimizer. Rewrite the script below for high-fidelity TTS.

      RULES:
      1. Use "..." for brief pauses.
      2. Use ALL CAPS for subtle emphasis.
      3. OUTPUT ONLY THE SCRIPT. NO markdown, NO code blocks, NO intro.

      Script: "${text}"`,
    });

    let cleaned = response.text?.trim() || text;
    cleaned = cleaned.replace(/^(Optimized script:|Script:|Neural output:|Here is the script:|Here is your script:)\s*/i, '');
    cleaned = cleaned.replace(/```[a-z]*\n?|```/gi, '');

    return sanitizeForTTS(cleaned);
  } catch (e) {
    return sanitizeForTTS(text);
  }
};

export const generateTTS = async (text: string, voiceName: string, settings?: VoiceSettings) => {
  const sanitizedText = sanitizeForTTS(text);

  if (!sanitizedText || sanitizedText.length < 2) {
    return null;
  }

  const pitchDesc = settings?.pitch && settings.pitch > 1.2 ? "high-pitched" : (settings?.pitch && settings.pitch < 0.8 ? "low-pitched" : "natural pitch");
  const rateDesc = settings?.rate && settings.rate > 1.3 ? "fast-paced" : (settings?.rate && settings.rate < 0.7 ? "slowly" : "natural speed");
  const styleDesc = settings?.style || 'expressive';
  const accentDesc = settings?.accent || 'natural';

  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `[VOICE_COMMAND: style=${styleDesc}, pitch=${pitchDesc}, rate=${rateDesc}, accent=${accentDesc}] SPEAK_CLEANLY: ${sanitizedText}` }] }],
      config: {
        systemInstruction: `You are a high-performance TTS engine. Your ONLY output is raw PCM audio. 
        - Strict Rule: NEVER output text or conversational acknowledgments.
        - Style: ${styleDesc}.
        - Prosody: Use a ${pitchDesc} voice and speak ${rateDesc}.
        - Accent: Deliver the speech with a ${accentDesc} inflection.
        - Performance: If the text contains emotional markers, synthesize with appropriate dramatic weight.`,
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const audioPart = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
    if (!audioPart) throw new Error("TTS_REFUSAL");
    return audioPart.inlineData.data;
  } catch (e: any) {
    if (e.message?.includes("non-audio response") || e.message?.includes("flow_id")) {
      throw new Error("TTS_REFUSAL");
    }
    return handleApiError(e);
  }
};

export const classifyVoice = async (base64Audio: string, mimeType: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Audio.split(',')[1], mimeType } },
          { text: `Analyze this audio sample for voice cloning. Extract forensic vocal metadata.

            1. IDENTIFY BIOLOGICAL GENDER (Strictly MALE or FEMALE).
            2. ANALYZE TIMBRE (Bright, Dark, Silky, Breathy, Nasal, Gravelly).
            3. ANALYZE PITCH CENTER (Low/Bass, Mid/Baritone, High/Tenor for males; Low/Contralto, Mid/Mezzo, High/Soprano for females).
            4. DETECT ACCENT (General American, RP British, Australian, etc.)

            MATCH TO CLOSEST GEMINI NEURAL PROFILE:
            - 'Puck': Youthful male, high pitch, bright.
            - 'Charon': Deep male, bass/baritone, authoritative.
            - 'Zephyr': Neutral male, balanced.
            - 'Fenrir': Gravelly male, textured, intense.
            - 'Kore': Calm female, professional, lower-mid pitch.
            - 'Aoide': Bright female, melodic, high pitch.

            STRICT GENDER LOCK: If source is female, MUST be Kore or Aoide. If male, MUST be Puck, Charon, Zephyr, or Fenrir.

            RETURN JSON ONLY:
            {
              "id": "ProfileName",
              "gender": "male" | "female",
              "traits": ["trait1", "trait2"],
              "summary": "One line descriptive summary",
              "suggestedSettings": {
                "pitch": number, // 0.8 to 1.2
                "rate": number,  // 0.9 to 1.1
                "style": "neutral" | "expressive" | "calm" | "authoritative" | "whisper" | "dramatic" | "storyteller"
              }
            }` }
        ]
      },
      config: {
        responseMimeType: "application/json"
      }
    });

    const result = JSON.parse(response.text || '{}');
    const validVoices = ['Puck', 'Charon', 'Zephyr', 'Fenrir', 'Kore', 'Aoide'];
    const matchedId = validVoices.find(v => v === result.id) || 'Zephyr';

    return { 
      id: matchedId, 
      gender: result.gender || 'neutral',
      traits: result.traits || [], 
      summary: result.summary || "Balanced Neural Profile",
      suggestedSettings: result.suggestedSettings || { pitch: 1.0, rate: 1.0, style: 'expressive' }
    };
  } catch (e) { 
    console.error("Forensic analysis failed", e);
    return { 
      id: 'Zephyr', 
      gender: 'male',
      traits: ["Standard"], 
      summary: "Standard Balanced Profile",
      suggestedSettings: { pitch: 1.0, rate: 1.0, style: 'neutral' }
    };
  }
};

export const generateVideo = async (prompt: string, aspectRatio: '16:9' | '9:16', startImage?: string) => {
  try {
    const ai = getAI();
    const payload: any = {
      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt || 'A cinematic scene',
      config: { numberOfVideos: 1, resolution: '720p', aspectRatio }
    };
    if (startImage) payload.image = { imageBytes: startImage.split(',')[1], mimeType: 'image/png' };
    let operation = await ai.models.generateVideos(payload);
    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }
    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
  } catch (e) { return handleApiError(e); }
};

export const generateImage = async (prompt: string, size: '1K' | '2K' | '4K', useNanoPro: boolean = false) => {
  try {
    const ai = getAI();
    const model = (useNanoPro || size !== '1K') ? 'gemini-3-pro-image-preview' : 'gemini-2.5-flash-image';
    const imageConfig: any = { aspectRatio: "1:1" };
    if (model === 'gemini-3-pro-image-preview') imageConfig.imageSize = size;
    const response = await ai.models.generateContent({
      model,
      contents: { parts: [{ text: prompt }] },
      config: { imageConfig },
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    return null;
  } catch (e) { return handleApiError(e); }
};

export const analyzeMedia = async (fileBase64: string, mimeType: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { data: fileBase64.split(',')[1], mimeType } },
