          <div className="max-w-2xl w-full glass-panel rounded-[2.5rem] p-10 space-y-8 border-indigo-500/20 shadow-2xl animate-in zoom-in-95 overflow-y-auto max-h-[90vh] custom-scrollbar">
            <div className="text-center space-y-2">
              <div className="w-20 h-20 rounded-3xl accent-gradient mx-auto flex items-center justify-center text-3xl shadow-lg">🧬</div>
