import React, { useState, useRef } from 'react';
import { ELEVEN_LABS_VOICES, VoiceProfile, VoiceSettings, DEFAULT_SETTINGS } from '../types';
import { generateTTS, classifyVoice, enhanceTextForSpeech, summarizeForVisuals, generateImage } from '../services/geminiService';

const TTSView: React.FC = () => {
  const [text, setText] = useState('');
  const [selectedVoice, setSelectedVoice] = useState<VoiceProfile>(ELEVEN_LABS_VOICES.find(v => v.name === 'Brain') || ELEVEN_LABS_VOICES[0]);
  const [loading, setLoading] = useState(false);
  const [cloning, setCloning] = useState(false);
  const [cloningStatus, setCloningStatus] = useState('');
  const [pendingClone, setPendingClone] = useState<VoiceProfile | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [visualUrl, setVisualUrl] = useState<string | null>(null);
  const [shouldEnhance, setShouldEnhance] = useState(true);
  const [shouldGenerateVisual, setShouldGenerateVisual] = useState(true);
  const [clonedVoices, setClonedVoices] = useState<VoiceProfile[]>(ELEVEN_LABS_VOICES);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [isSettingsOpen, setIsSettingsOpen] = useState(true);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const encodeWAV = (samples: Float32Array, sampleRate: number) => {
    const buffer = new ArrayBuffer(44 + samples.length * 2);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) v.setUint8(offset + i, string.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 32 + samples.length * 2, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, samples.length * 2, true);
    let offset = 44;
    for (let i = 0; i < samples.length; i++, offset += 2) {
      const s = Math.max(-1, Math.min(1, samples[i]));
      view.setInt16(offset, s < 0 ? s * 0x8000 : s * 0x7FFF, true);
    }
    return buffer;
  };

  const processAudioData = (base64Audio: string) => {
    try {
      const binaryString = atob(base64Audio);
      const len = binaryString.length;
      // Byte alignment fix for 500 errors
      const bufferLen = Math.floor(len / 2) * 2;
      const bytes = new Uint8Array(bufferLen);
      for (let i = 0; i < bufferLen; i++) bytes[i] = binaryString.charCodeAt(i);
      const int16Data = new Int16Array(bytes.buffer, 0, bufferLen / 2);
      const floatData = new Float32Array(int16Data.length);
      for (let i = 0; i < int16Data.length; i++) floatData[i] = int16Data[i] / 32768.0;
      const wavBuffer = encodeWAV(floatData, 24000);
      return URL.createObjectURL(new Blob([wavBuffer], { type: 'audio/wav' }));
    } catch (e) {
      console.error("Audio processing failed:", e);
      return null;
    }
  };

  const updateSelectedVoiceSetting = <K extends keyof VoiceSettings>(key: K, value: VoiceSettings[K]) => {
    const updated = { ...selectedVoice, settings: { ...selectedVoice.settings, [key]: value } };
    setSelectedVoice(updated);
    setClonedVoices(prev => prev.map(v => v.id === updated.id ? updated : v));
  };

  const updatePendingCloneSetting = <K extends keyof VoiceSettings>(key: K, value: VoiceSettings[K]) => {
    if (!pendingClone) return;
    setPendingClone({ ...pendingClone, settings: { ...pendingClone.settings, [key]: value } });
  };

  const handleGenerate = async () => {
    if (!text || text.trim().length < 2) {
      setErrorMsg("Script too short for neural synthesis.");
      return;
    }
    setLoading(true);
    setErrorMsg(null);
    setAudioUrl(null);
    setVisualUrl(null);

    try {
      let processingText = text;
      if (shouldEnhance) processingText = await enhanceTextForSpeech(text);

      let base64Audio: string | null = null;
      try {
        base64Audio = await generateTTS(processingText, selectedVoice.geminiVoice, selectedVoice.settings);
      } catch (synthErr: any) {
        if (synthErr.message === 'TTS_REFUSAL') {
          // Fallback to simplified generation if the enhanced version triggers a safety filter
          base64Audio = await generateTTS(text.slice(0, 400), selectedVoice.geminiVoice, selectedVoice.settings);
        } else {
          throw synthErr;
        }
      }

      let visualPromise = Promise.resolve(null as string | null);
      if (shouldGenerateVisual) {
        visualPromise = summarizeForVisuals(text).then(prompt => generateImage(prompt, '1K', false));
      }
      const imageResult = await visualPromise;

      if (base64Audio) {
        const url = processAudioData(base64Audio);
        if (url) {
          setAudioUrl(url);
          if (audioRef.current) {
            audioRef.current.load();
            audioRef.current.play();
          }
        } else setErrorMsg("Vocal stream corruption detected.");
      } else {
        setErrorMsg("The neural engine rejected this script. Try adjusting the content.");
      }

      if (imageResult) setVisualUrl(imageResult);
    } catch (err: any) {
      setErrorMsg(err.message || "Synthesis failed. Check project key status.");
    } finally {
      setLoading(false);
    }
  };

  const handleCloneVoice = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setCloning(true);
    setErrorMsg(null);
    setCloningStatus('Extracting Vocal DNA...');
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = reader.result as string;
        const analysis = await classifyVoice(base64, file.type);

        const newVoice: VoiceProfile = {
          id: Math.random().toString(36).substr(2, 9),
          name: `Clone: ${file.name.split('.')[0]}`,
          geminiVoice: analysis.id,
          description: analysis.summary,
          gender: analysis.gender as any,
          traits: analysis.traits,
          settings: { ...DEFAULT_SETTINGS, ...analysis.suggestedSettings }
        };
        setPendingClone(newVoice);
        setCloning(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      };
      reader.readAsDataURL(file);
    } catch (error) {
      setErrorMsg("Vocal analysis failed. Audio sample must be clear.");
      setCloning(false);
    }
  };

  const handlePreviewNeuralTest = async () => {
    if (!pendingClone) return;
    setCloningStatus('Synthesizing Test Sample...');
    setCloning(true);
    try {
      const base64 = await generateTTS("Vocal identity verification in progress. Please confirm replication accuracy.", pendingClone.geminiVoice, pendingClone.settings);
      if (base64) {
        const url = processAudioData(base64);
        if (url) {
          const audio = new Audio(url);
          audio.volume = pendingClone.settings.volume;
          audio.play();
        }
      }
    } catch (e) {
      setErrorMsg("Preview synthesis failed.");
    } finally {
      setCloning(false);
    }
  };

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20">

      {/* Forensic Clone Verification Wizard */}
      {pendingClone && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-gray-950/95 backdrop-blur-2xl p-4">
          <div className="max-w-3xl w-full glass-panel rounded-[3rem] p-12 space-y-10 border-indigo-500/30 shadow-[0_0_100px_rgba(99,102,241,0.2)] animate-in zoom-in-95 overflow-y-auto max-h-[90vh] custom-scrollbar">
            <div className="text-center space-y-3">
              <div className="w-24 h-24 rounded-3xl accent-gradient mx-auto flex items-center justify-center text-4xl shadow-2xl animate-pulse">🧬</div>
              <h2 className="text-4xl font-bold font-outfit text-white">Vocal Identity Mapping</h2>
              <p className="text-gray-400 max-w-md mx-auto">Forensic characteristics extracted. Tweak the neural settings to match the source sample perfectly.</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
               <div className="space-y-8 bg-white/5 p-8 rounded-[2.5rem] border border-white/5">
                  <div className="flex justify-between items-center">
                    <span className="text-xs font-bold text-indigo-400 uppercase tracking-widest">Base Neural ID: {pendingClone.geminiVoice}</span>
                    <span className={`text-[10px] px-3 py-1 rounded-full font-bold uppercase ${pendingClone.gender === 'female' ? 'bg-pink-500/20 text-pink-400' : 'bg-blue-500/20 text-blue-400'}`}>
                      {pendingClone.gender} Identified
                    </span>
                  </div>

                  <div className="space-y-3">
                    <label className="text-[10px] font-bold text-gray-500 uppercase tracking-[0.2em]">Profile Label</label>
                    <input 
                      type="text" 
                      value={pendingClone.name} 
                      onChange={(e) => setPendingClone({...pendingClone, name: e.target.value})}
                      className="w-full bg-black/40 border border-white/10 rounded-2xl p-4 text-white font-bold focus:border-indigo-500/50 outline-none transition-all"
                    />
                  </div>

                  <div className="space-y-4">
                    <label className="text-[10px] font-bold text-gray-500 uppercase tracking-[0.2em]">Detected Characteristics</label>
                    <div className="flex flex-wrap gap-2">
                      {pendingClone.traits?.map(trait => (
                        <span key={trait} className="px-3 py-1 bg-indigo-500/10 border border-indigo-500/20 rounded-lg text-[10px] text-indigo-300 font-bold uppercase">{trait}</span>
                      ))}
                    </div>
                    <p className="text-xs text-gray-400 italic font-medium leading-relaxed">"{pendingClone.description}"</p>
                  </div>
               </div>

               <div className="space-y-8">
                  <div className="space-y-6">
                    <div className="space-y-3">
                      <div className="flex justify-between text-[10px] font-bold uppercase text-gray-400 tracking-widest">
                        <span>Pitch Calibration</span>
                        <span className="text-indigo-400">{pendingClone.settings.pitch}x</span>
                      </div>
                      <input 
                        type="range" min="0.5" max="1.5" step="0.05" 
                        value={pendingClone.settings.pitch}
                        onChange={(e) => updatePendingCloneSetting('pitch', parseFloat(e.target.value))}
                        className="w-full accent-indigo-500"
                      />
                    </div>
                    <div className="space-y-3">
                      <div className="flex justify-between text-[10px] font-bold uppercase text-gray-400 tracking-widest">
                        <span>Speaking Cadence</span>
                        <span className="text-indigo-400">{pendingClone.settings.rate}x</span>
                      </div>
                      <input 
                        type="range" min="0.5" max="1.5" step="0.05" 
                        value={pendingClone.settings.rate}
                        onChange={(e) => updatePendingCloneSetting('rate', parseFloat(e.target.value))}
                        className="w-full accent-indigo-500"
                      />
                    </div>
                    <div className="space-y-3">
                      <label className="text-[10px] font-bold text-gray-500 uppercase tracking-[0.2em]">Accents & Nuance</label>
                      <div className="flex flex-wrap gap-2">
                        {(['natural', 'american', 'british', 'australian', 'soft', 'strong'] as const).map(acc => (
                          <button
                            key={acc}
                            onClick={() => updatePendingCloneSetting('accent', acc)}
                            className={`px-3 py-1.5 rounded-xl text-[10px] font-bold uppercase border transition-all ${pendingClone.settings.accent === acc ? 'bg-indigo-500 border-indigo-500 text-white shadow-lg' : 'bg-white/5 border-white/10 text-gray-500 hover:text-gray-300'}`}
                          >
                            {acc}
                          </button>
                        ))}
                      </div>
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-4 pt-4">
                    <button 
                      onClick={handlePreviewNeuralTest}
                      disabled={cloning}
                      className="py-5 bg-white/5 border border-white/10 rounded-3xl font-bold text-sm hover:bg-white/10 transition-all flex items-center justify-center gap-3 group"
                    >
                      {cloning ? <div className="w-5 h-5 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin"></div> : (
                        <><svg className="w-6 h-6 text-indigo-400 group-hover:scale-110 transition-transform" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-2 14.5v-9l6 4.5-6 4.5z"/></svg> Neural Test</>
                      )}
                    </button>
                    <button 
                      onClick={() => { setClonedVoices([pendingClone, ...clonedVoices]); setSelectedVoice(pendingClone); setPendingClone(null); }}
                      className="py-5 accent-gradient rounded-3xl font-bold text-sm hover:shadow-[0_0_30px_rgba(99,102,241,0.5)] transition-all hover:scale-[1.02] active:scale-[0.98]"
                    >
                      Finalize Identity
                    </button>
                  </div>
                  <button onClick={() => setPendingClone(null)} className="w-full text-xs text-gray-600 font-bold uppercase tracking-[0.3em] hover:text-white transition-colors">Discard Analysis</button>
               </div>
            </div>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">

        {/* Main Editor */}
        <div className="lg:col-span-8 space-y-8">
          <div className="space-y-6">
            <div className="flex items-center justify-between px-2">
              <label className="text-sm font-bold text-gray-500 uppercase tracking-[0.3em]">Master Narrator Engine</label>
              <div className="flex gap-4">
                 <button 
                  onClick={() => setShouldEnhance(!shouldEnhance)}
                  className={`flex items-center gap-2 text-[10px] font-bold px-4 py-2 rounded-full border transition-all ${shouldEnhance ? 'bg-indigo-500/20 border-indigo-500 text-indigo-400 shadow-[0_0_15px_rgba(99,102,241,0.2)]' : 'bg-white/5 border-white/10 text-gray-600 hover:text-gray-400'}`}
                 >
                   {shouldEnhance ? '✨ ENHANCE V3 ACTIVE' : 'RAW SCRIPT MODE'}
                 </button>
                 <button 
                  onClick={() => setIsSettingsOpen(!isSettingsOpen)}
                  className={`flex items-center gap-2 text-[10px] font-bold px-4 py-2 rounded-full border transition-all ${isSettingsOpen ? 'bg-purple-500/20 border-purple-500 text-purple-400 shadow-[0_0_15px_rgba(168,85,247,0.2)]' : 'bg-white/5 border-white/10 text-gray-600 hover:text-gray-400'}`}
                 >
                   ⚙️ MASTER SETTINGS
                 </button>
              </div>
            </div>

            {isSettingsOpen && (
              <div className="p-10 glass-panel rounded-[2.5rem] border-purple-500/20 animate-in slide-in-from-top-4 space-y-10 shadow-2xl relative overflow-hidden group">
                <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:opacity-20 transition-opacity pointer-events-none">
                  <svg className="w-24 h-24" fill="currentColor" viewBox="0 0 24 24"><path d="M12 15a3 3 0 100-6 3 3 0 000 6z"/><path fillRule="evenodd" d="M1.323 11.447C2.811 6.976 7.028 3.75 12.001 3.75c4.97 0 9.185 3.223 10.675 7.69.12.362.12.752 0 1.113-1.487 4.471-5.705 7.697-10.677 7.697-4.97 0-9.186-3.223-10.675-7.69a1.762 1.762 0 010-1.113zM17.25 12a5.25 5.25 0 11-10.5 0 5.25 5.25 0 0110.5 0z" clipRule="evenodd"/></svg>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
                  <div className="space-y-4">
                    <div className="flex justify-between text-xs font-bold uppercase text-gray-500 tracking-widest">
                      <span>Neural Pitch</span>
                      <span className="text-purple-400">{selectedVoice.settings.pitch}x</span>
                    </div>
                    <input 
                      type="range" min="0.5" max="1.5" step="0.05" 
                      value={selectedVoice.settings.pitch}
                      onChange={(e) => updateSelectedVoiceSetting('pitch', parseFloat(e.target.value))}
                      className="w-full accent-purple-500 h-1.5 bg-white/5 rounded-full"
                    />
                  </div>
                  <div className="space-y-4">
                    <div className="flex justify-between text-xs font-bold uppercase text-gray-500 tracking-widest">
                      <span>Speaking Rate</span>
                      <span className="text-purple-400">{selectedVoice.settings.rate}x</span>
                    </div>
                    <input 
                      type="range" min="0.5" max="2.0" step="0.05" 
                      value={selectedVoice.settings.rate}
                      onChange={(e) => updateSelectedVoiceSetting('rate', parseFloat(e.target.value))}
                      className="w-full accent-purple-500 h-1.5 bg-white/5 rounded-full"
                    />
                  </div>
                  <div className="space-y-4">
                    <div className="flex justify-between text-xs font-bold uppercase text-gray-500 tracking-widest">
                      <span>Neural Gain</span>
                      <span className="text-purple-400">{Math.round(selectedVoice.settings.volume * 100)}%</span>
                    </div>
                    <input 
                      type="range" min="0" max="1" step="0.05" 
                      value={selectedVoice.settings.volume}
                      onChange={(e) => updateSelectedVoiceSetting('volume', parseFloat(e.target.value))}
                      className="w-full accent-purple-500 h-1.5 bg-white/5 rounded-full"
                    />
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-10 pt-8 border-t border-white/5">
                  <div className="space-y-4">
                    <label className="text-[10px] font-bold text-gray-600 uppercase tracking-[0.2em]">Emotional Prosody</label>
                    <div className="flex flex-wrap gap-2">
                      {(['neutral', 'expressive', 'calm', 'authoritative', 'whisper', 'dramatic', 'storyteller'] as const).map(style => (
                        <button
                          key={style}
                          onClick={() => updateSelectedVoiceSetting('style', style)}
                          className={`px-4 py-2 rounded-xl text-[10px] font-bold uppercase border transition-all ${selectedVoice.settings.style === style ? 'bg-purple-500 border-purple-500 text-white shadow-lg' : 'bg-white/5 border-white/10 text-gray-600 hover:text-gray-400'}`}
                        >
                          {style}
                        </button>
                      ))}
                    </div>
                  </div>
                  <div className="space-y-4">
                    <label className="text-[10px] font-bold text-gray-600 uppercase tracking-[0.2em]">Accent Inflection</label>
                    <div className="flex flex-wrap gap-2">
                      {(['natural', 'american', 'british', 'australian', 'soft', 'strong'] as const).map(accent => (
                        <button
                          key={accent}
                          onClick={() => updateSelectedVoiceSetting('accent', accent)}
                          className={`px-4 py-2 rounded-xl text-[10px] font-bold uppercase border transition-all ${selectedVoice.settings.accent === accent ? 'bg-purple-500 border-purple-500 text-white shadow-lg' : 'bg-white/5 border-white/10 text-gray-600 hover:text-gray-400'}`}
                        >
                          {accent}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            )}

            <div className="relative group">
              <textarea
                value={text}
                onChange={(e) => { setText(e.target.value); if (errorMsg) setErrorMsg(null); }}
                placeholder="The narrative is the primary substrate. Inject your script here for high-precision neural rendering..."
                className="w-full h-80 p-12 glass-panel rounded-[3rem] border-white/10 focus:border-indigo-500/50 outline-none resize-none transition-all text-xl leading-relaxed shadow-2xl font-light placeholder:text-gray-700"
              />
              <div className="absolute bottom-6 right-8 text-[10px] font-bold text-gray-600 tracking-widest uppercase pointer-events-none">
                {text.length} Characters • Neural Ready
              </div>
            </div>
          </div>

          <button
            onClick={handleGenerate}
            disabled={loading || !text}
            className={`w-full py-8 accent-gradient rounded-[2rem] font-bold flex items-center justify-center gap-4 transition-all text-2xl shadow-[0_20px_60px_rgba(99,102,241,0.3)] group ${loading ? 'opacity-50 cursor-wait' : 'hover:scale-[1.01] active:scale-[0.99]'}`}
          >
            {loading ? (
              <><div className="w-8 h-8 border-4 border-white/30 border-t-white rounded-full animate-spin" /> MAPPING NEURAL SYNC...</>
            ) : (
              <><svg className="w-7 h-7 group-hover:rotate-12 transition-transform" fill="currentColor" viewBox="0 0 24 24"><path d="M12 3v10.55c-.59-.34-1.27-.55-2-.55-2.21 0-4 1.79-4 4s1.79 4 4 4 4-1.79 4-4V7h4V3h-6z"/></svg> GENERATE MASTER AUDIO</>
            )}
          </button>

          {(audioUrl || visualUrl) && (
            <div className="grid grid-cols-1 md:grid-cols-12 gap-8 animate-in slide-in-from-top-12 duration-700">
              {visualUrl && (
                <div className="md:col-span-5 aspect-square glass-panel rounded-[3rem] border-emerald-500/20 overflow-hidden shadow-2xl group relative">
                  <img src={visualUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-2000" alt="Script Visual" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex items-end p-8">
                    <p className="text-[10px] font-bold text-white uppercase tracking-widest">Synced Scene Visualizer</p>
                  </div>
                </div>
              )}
              <div className={`${visualUrl ? 'md:col-span-7' : 'md:col-span-12'} p-12 glass-panel rounded-[3rem] border-indigo-500/30 flex flex-col justify-between shadow-2xl bg-indigo-500/5`}>
                <div className="space-y-10">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-6">
                      <div className={`w-24 h-24 rounded-[2rem] flex items-center justify-center font-bold text-4xl shadow-2xl transition-all ${selectedVoice.gender === 'female' ? 'bg-pink-500/20 text-pink-400' : 'bg-blue-500/20 text-blue-400'}`}>
                        {selectedVoice.name.charAt(0)}
                      </div>
                      <div className="space-y-1">
                        <h4 className="font-bold text-white text-3xl font-outfit tracking-tight">{selectedVoice.name}</h4>
                        <p className="text-[10px] text-gray-500 uppercase tracking-[0.4em]">Neural Output • Forensic Precision</p>
                      </div>
                    </div>
                    {audioUrl && (
                      <a href={audioUrl} download={`${selectedVoice.name}-master.wav`} className="p-6 bg-indigo-500 rounded-[2rem] hover:bg-indigo-600 transition-all text-white shadow-2xl hover:scale-105 active:scale-95 group">
                        <svg className="w-8 h-8 group-hover:translate-y-0.5 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                      </a>
                    )}
                  </div>

                  <div className="bg-black/60 p-10 rounded-[2.5rem] border border-white/5 shadow-inner group">
                    <div className="flex items-center gap-4 mb-8">
                       <div className="flex gap-1.5 h-6">
                          <div className="w-1.5 h-full bg-indigo-500/40 rounded-full animate-bounce"></div>
                          <div className="w-1.5 h-4/5 bg-indigo-500 rounded-full animate-bounce delay-75"></div>
                          <div className="w-1.5 h-full bg-indigo-500/60 rounded-full animate-bounce delay-150"></div>
                       </div>
                       <span className="text-[10px] text-indigo-400 font-bold uppercase tracking-[0.2em]">Live Neural Stream Active</span>
                    </div>
                    {audioUrl && <audio ref={audioRef} src={audioUrl} controls className="w-full accent-indigo-500" />}
                  </div>
                </div>

                <div className="mt-8 flex items-center gap-4 text-gray-600 text-[10px] font-bold uppercase tracking-widest border-t border-white/5 pt-8">
                   <div className="flex items-center gap-2">
                     <div className="w-2 h-2 rounded-full bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.8)]"></div>
                     Pitch Lock Active
                   </div>
                   <div className="w-1 h-1 rounded-full bg-gray-800"></div>
                   <div className="flex items-center gap-2">
