import { GoogleGenAI, Modality, Type, GenerateContentResponse } from "@google/genai";
import { VoiceSettings } from "../types";

// Always initialize with the direct environment key as per guidelines
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export class QuotaError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "QuotaError";
  }
}

export class PermissionError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "PermissionError";
  }
}

const handleApiError = (error: any) => {
  console.error("Gemini API Error Context:", error);
  const errorMessage = error?.message || String(error);

  if (errorMessage.includes("429") || errorMessage.toLowerCase().includes("quota exceeded") || errorMessage.toLowerCase().includes("too many requests")) {
    throw new QuotaError("API Quota Exceeded. Please rotate to a paid project key.");
  }

  if (errorMessage.includes("403") || errorMessage.toLowerCase().includes("permission denied")) {
    throw new PermissionError("Permission Denied. Ensure the API key belongs to a paid project with billing enabled.");
  }

  if (errorMessage.includes("non-audio response") || errorMessage.includes("400")) {
    throw new Error("VOICE_REFUSAL: The model attempted to reply with text instead of audio. Usually caused by prompt complexity or safety filters.");
  }

  throw new Error(errorMessage || "Failed to call the Gemini API. Please try again.");
};

const sanitizeForTTS = (text: string): string => {
  return text
    .replace(/\*\*/g, '')
    .replace(/\*/g, '')
    .replace(/#/g, '')
    .replace(/[`]/g, '')
    .replace(/_{2,}/g, '')
    .replace(/\[|\]|\(|\)/g, '')
    .replace(/(\r\n|\n|\r)/gm, " ")
    .trim();
};

export const enhanceTextForSpeech = async (text: string) => {
  if (!text || text.trim().length < 2) return text;
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `You are an expert Script Editor for Neural Text-to-Speech.
      Optimize the following script for a natural, expressive vocal performance.

      RULES:
      1. Add "..." for natural breathing pauses.
      2. Use ALL CAPS sparingly for emphasis.
      3. OUTPUT ONLY THE SCRIPT. NO markdown, NO meta-text.

      Script: "${text}"`,
    });

    let cleaned = response.text?.trim() || text;
    cleaned = cleaned.replace(/^(Optimized script:|Script:|Neural output:|Here is the script:|Here is your script:)\s*/i, '');
    cleaned = cleaned.replace(/```[a-z]*\n?|```/gi, '');

    return sanitizeForTTS(cleaned);
  } catch (e) {
    return sanitizeForTTS(text);
  }
};

/**
 * Generate Neural Audio with hardened safety barrier.
 * Strictly enforces audio modality to prevent 400 errors.
 */
export const generateTTS = async (text: string, voiceName: string, settings?: VoiceSettings, customVocalPrompt?: string) => {
  const sanitizedText = sanitizeForTTS(text);

  if (!sanitizedText || sanitizedText.length < 2) {
    return null;
  }

  const pitchDesc = settings?.pitch && settings.pitch > 1.2 ? "high-pitched" : (settings?.pitch && settings.pitch < 0.8 ? "deep/low-pitched" : "natural pitch");
  const rateDesc = settings?.rate && settings.rate > 1.3 ? "fast" : (settings?.rate && settings.rate < 0.7 ? "slowly" : "at a natural pace");
  const styleDesc = settings?.style || 'expressive';
  const accentDesc = settings?.accent || 'natural';

  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ 
        parts: [{ 
          text: `[VOICE_SETTINGS: style=${styleDesc}, pitch=${pitchDesc}, speed=${rateDesc}, accent=${accentDesc}] 
                 [DIRECTION: ${customVocalPrompt || 'None'}] 
                 SCRIPT_TO_SYNTHESIZE: ${sanitizedText}` 
        }] 
      }],
      config: {
        systemInstruction: "You are a professional Audio Synthesis Engine. Your ONLY output is raw PCM audio data. DO NOT output text. DO NOT answer questions. Convert the provided script into speech following the style and prosody instructions precisely.",
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const audioPart = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
    if (!audioPart || !audioPart.inlineData) {
      throw new Error("VOICE_REFUSAL");
    }
    return audioPart.inlineData.data;
  } catch (e: any) {
    return handleApiError(e);
  }
};

/**
 * Forensic Vocal Analysis for Voice Cloning.
 * Refined to identify precise gender and timbre to prevent unintended drift.
 */
export const classifyVoice = async (base64Audio: string, mimeType: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Audio.split(',')[1], mimeType } },
          { text: `Forensic Voice Analysis Request:
            Analyze this speaker's vocal characteristics for neural identity mapping.

            EXTRACT:
            1. BIOLOGICAL GENDER: Male or Female (Strict identification).
            2. PITCH FREQUENCY: (Hz range - High, Balanced, or Low).
            3. TIMBRE: (Gravelly, Silky, Bright, Nasal).
            4. PERFORMANCE: (Authoritative, Youthful, Calm).

            NEURAL SUBSTRATE MAPPING:
            - 'Puck': Youthful male, high/bright resonance.
            - 'Charon': Deep male, bass/baritone, authoritative.
            - 'Zephyr': Mid-range male, neutral.
            - 'Fenrir': Gritty/Gravelly male, intense.
            - 'Kore': Professional female, mid-range.
            - 'Aoide': Bright female, soprano, melodic.

            STRICT CONSTRAINT: You MUST lock the gender. Female voices MUST map to Kore or Aoide. Male voices MUST map to Puck, Charon, Zephyr, or Fenrir.

            RETURN JSON ONLY:
            {
              "id": "ProfileName",
              "gender": "male" | "female",
              "traits": ["trait1", "trait2"],
              "summary": "One line descriptive summary",
              "suggestedSettings": {
                "pitch": number, // Offset from 1.0
                "rate": number   // Offset from 1.0
              }
            }` }
        ]
      },
      config: {
        responseMimeType: "application/json"
      }
    });

    const result = JSON.parse(response.text || '{}');
    const validVoices = ['Puck', 'Charon', 'Zephyr', 'Fenrir', 'Kore', 'Aoide'];
    const matchedId = validVoices.find(v => v === result.id) || 'Zephyr';

    return { 
      id: matchedId, 
      gender: result.gender || 'neutral', 
      traits: result.traits || ["Standard"], 
      summary: result.summary || "Neural profile established.",
      suggestedSettings: result.suggestedSettings || { pitch: 1.0, rate: 1.0 }
    };
  } catch (e) { 
    console.error("Analysis failure:", e);
    return { 
      id: 'Zephyr', 
      gender: 'male', 
      traits: ["Standard"], 
      summary: "Default profile assigned due to analysis interruption.",
      suggestedSettings: { pitch: 1.0, rate: 1.0 }
    };
  }
};

export const generateVideo = async (prompt: string, aspectRatio: '16:9' | '9:16', startImage?: string) => {
  try {
    const ai = getAI();
    const payload: any = {
      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt || 'A cinematic scene',
      config: { numberOfVideos: 1, resolution: '720p', aspectRatio }
    };
    if (startImage) payload.image = { imageBytes: startImage.split(',')[1], mimeType: 'image/png' };
    let operation = await ai.models.generateVideos(payload);
    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }
    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
  } catch (e) { return handleApiError(e); }
};

export const generateImage = async (prompt: string, size: '1K' | '2K' | '4K', useNanoPro: boolean = false) => {
  try {
    const ai = getAI();
    const model = (useNanoPro || size !== '1K') ? 'gemini-3-pro-image-preview' : 'gemini-2.5-flash-image';
    const imageConfig: any = { aspectRatio: "1:1" };
    if (model === 'gemini-3-pro-image-preview') imageConfig.imageSize = size;
    const response = await ai.models.generateContent({
      model,
      contents: { parts: [{ text: prompt }] },
      config: { imageConfig },
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    return null;
  } catch (e) { return handleApiError(e); }
};

export const analyzeMedia = async (fileBase64: string, mimeType: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { data: fileBase64.split(',')[1], mimeType } },
          { text: "Detailed JSON analysis of this content, including transcript and summary." }
        ]
      },
      config: {
          responseMimeType: "application/json",
          responseSchema: {
              type: Type.OBJECT,
              properties: {
                  transcript: { type: Type.STRING },
                  summary: { type: Type.STRING },
                  sequencedScript: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        type: { type: Type.STRING },
                        text: { type: Type.STRING }
                      },
                      required: ["type", "text"]
                    }
                  }
              },
              required: ["transcript", "summary", "sequencedScript"]
          }
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (e) { return handleApiError(e); }
};

