                    <button onClick={() => setPendingClone(null)} className="py-2 text-xs text-gray-600 font-bold uppercase tracking-[0.3em] hover:text-white transition-colors">Discard Analysis</button>
                  </div>
               </div>
            </div>
          </div>
        </div>
