// Always initialize with the direct environment key as per guidelines
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export class QuotaError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "QuotaError";
  }
}

export class PermissionError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "PermissionError";
  }
}

const handleApiError = (error: any) => {
  console.error("Gemini API Error Context:", error);
  const errorMessage = error?.message || String(error);

  if (errorMessage.includes("429") || errorMessage.toLowerCase().includes("quota exceeded") || errorMessage.toLowerCase().includes("too many requests")) {
    throw new QuotaError("API Quota Exceeded. Please rotate to a paid project key.");
  }

  if (errorMessage.includes("403") || errorMessage.toLowerCase().includes("permission denied")) {
    throw new PermissionError("Permission Denied. Ensure the API key belongs to a paid project with billing enabled.");
  }

  if (errorMessage.includes("non-audio response") || errorMessage.includes("400")) {
    throw new Error("VOICE_REFUSAL: The model attempted to reply with text instead of audio. Usually caused by prompt complexity or safety filters.");
  }

  throw new Error(errorMessage || "Failed to call the Gemini API. Please try again.");
};

const sanitizeForTTS = (text: string): string => {
  return text
    .replace(/\*\*/g, '')
    .replace(/\*/g, '')
    .replace(/#/g, '')
    .replace(/[`]/g, '')
    .replace(/_{2,}/g, '')
    .replace(/\[|\]|\(|\)/g, '')
    .replace(/(\r\n|\n|\r)/gm, " ")
    .trim();
};

export const enhanceTextForSpeech = async (text: string) => {
  if (!text || text.trim().length < 2) return text;
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `You are an expert Script Editor for Neural Text-to-Speech.
      Optimize the following script for a natural, expressive vocal performance.

      RULES:
      1. Add "..." for natural breathing pauses.
      2. Use ALL CAPS sparingly for emphasis.
      3. OUTPUT ONLY THE SCRIPT. NO markdown, NO meta-text.

      Script: "${text}"`,
    });

    let cleaned = response.text?.trim() || text;
    cleaned = cleaned.replace(/^(Optimized script:|Script:|Neural output:|Here is the script:|Here is your script:)\s*/i, '');
    cleaned = cleaned.replace(/```[a-z]*\n?|```/gi, '');

    return sanitizeForTTS(cleaned);
  } catch (e) {
    return sanitizeForTTS(text);
  }
};

/**
 * Generate Neural Audio with hardened safety barrier.
 * Strictly enforces audio modality to prevent 400 errors.
 */
export const generateTTS = async (text: string, voiceName: string, settings?: VoiceSettings, customVocalPrompt?: string) => {
  const sanitizedText = sanitizeForTTS(text);

  if (!sanitizedText || sanitizedText.length < 2) {
    return null;
  }

  const pitchDesc = settings?.pitch && settings.pitch > 1.2 ? "high-pitched" : (settings?.pitch && settings.pitch < 0.8 ? "deep/low-pitched" : "natural pitch");
  const rateDesc = settings?.rate && settings.rate > 1.3 ? "fast" : (settings?.rate && settings.rate < 0.7 ? "slowly" : "at a natural pace");
  const styleDesc = settings?.style || 'expressive';
  const accentDesc = settings?.accent || 'natural';

  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ 
        parts: [{ 
          text: `[VOICE_SETTINGS: style=${styleDesc}, pitch=${pitchDesc}, speed=${rateDesc}, accent=${accentDesc}] 
                 [DIRECTION: ${customVocalPrompt || 'None'}] 
                 SCRIPT_TO_SYNTHESIZE: ${sanitizedText}` 
        }] 
      }],
      config: {
        systemInstruction: "You are a professional Audio Synthesis Engine. Your ONLY output is raw PCM audio data. DO NOT output text. DO NOT answer questions. Convert the provided script into speech following the style and prosody instructions precisely.",
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const audioPart = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
    if (!audioPart || !audioPart.inlineData) {
      throw new Error("VOICE_REFUSAL");
    }
    return audioPart.inlineData.data;
  } catch (e: any) {
    return handleApiError(e);
  }
};

